453→    }
454→
455→    case 'ASSEMBLY_DELETE_WITH_PARTS': {
456→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
457→      if (managedObject) {
458→        return sketchReducer(state, {
459→          type: 'OBJECT_DELETE',
460→          objectId: managedObject.id,
461→        });
462→      }
463→
464→      const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
465→      if (!assembly) return state;
466→
467→      return applyUpdate(state, {
468→        ...removePartsAndAssemblies(state.project, {
469→          partIds: assembly.partIds,
470→          assemblyIds: [assembly.id],
471→        }),
472→        updatedAt: new Date().toISOString(),
473→      });
474→    }
475→
476→    case 'ASSEMBLY_ADD_PART': {
477→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
478→      if (managedObject) return state;
479→
480→       const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
481→
482→      return applyUpdate(state, {
483→        ...state.project,
484→        updatedAt: new Date().toISOString(),
485→        assemblies: state.project.assemblies.map((assembly) => (
486→          assembly.id === action.assemblyId && !assembly.partIds.includes(action.partId)
487→            ? { ...assembly, partIds: [...assembly.partIds, action.partId] }
488→            : assembly
489→        )),
490→        parts: state.project.parts.map((part) => (
491→          part.id === action.partId
492→            ? { ...part, assemblyId: action.assemblyId, objectId: assembly?.objectId || part.objectId || null }
493→            : part
494→        )),
495→      });
496→    }
497→
498→    case 'ASSEMBLY_REMOVE_PART': {
499→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
500→      if (managedObject) return state;
501→
502→      return applyUpdate(state, {
503→        ...state.project,
504→        updatedAt: new Date().toISOString(),
505→        assemblies: state.project.assemblies.map((assembly) => (
506→          assembly.id === action.assemblyId
507→            ? { ...assembly, partIds: assembly.partIds.filter((id) => id !== action.partId) }
508→            : assembly
509→        )),
510→        parts: state.project.parts.map((part) => (
511→          part.id === action.partId && part.assemblyId === action.assemblyId
512→            ? { ...part, assemblyId: null }
513→            : part
514→        )),
515→      });
516→    }
517→
518→    case 'ASSEMBLY_CLONE': {
519→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
520→      if (managedObject) return state;
521→
522→      const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
523→      if (!assembly) return state;
524→
525→      const idMap = new Map();
526→      const newAssemblyId = generateId('asm');
527→      const newAssembly = {
528→        ...assembly,
529→        id: newAssemblyId,
530→        name: `${assembly.name} (copy)`,
531→        partIds: [],
532→        objectId: assembly.objectId || null,
533→        source: 'manual',
534→      };
535→
536→      const assemblyParts = state.project.parts.filter((part) => part.assemblyId === action.assemblyId);
537→      const clonedParts = [];
538→
539→      for (const part of assemblyParts) {
540→        const cloned = clonePart(part, idMap);
541→        cloned.assemblyId = newAssemblyId;
542→        clonedParts.push(cloned);
543→      }
544→
545→      for (const clonedPart of clonedParts) {
546→        if (clonedPart.parentId && idMap.has(clonedPart.parentId)) {
547→          clonedPart.parentId = idMap.get(clonedPart.parentId);
548→        }
549→      }
550→
551→      newAssembly.partIds = clonedParts.map((part) => part.id);
552→
553→      return applyUpdate(state, {
554→        ...state.project,
555→        updatedAt: new Date().toISOString(),
556→        parts: [...state.project.parts, ...clonedParts],
557→        assemblies: [...state.project.assemblies, newAssembly],
558→      });
559→    }
560→
561→    case 'OBJECT_UPDATE':
562→      return applyUpdate(state, {
563→        ...state.project,
564→        updatedAt: new Date().toISOString(),
565→        objects: (state.project.objects || []).map((object) => (
566→          object.id === action.object.id
567→            ? {
568→                ...object,
569→                ...action.object,
570→                templateParams: action.object.templateParams
571→                  ? { ...action.object.templateParams }
572→                  : object.templateParams,
573→                dimensions: action.object.dimensions
574→                  ? { ...action.object.dimensions }
575→                  : object.dimensions,
576→                updatedAt: new Date().toISOString(),
577→              }
578→            : object
579→        )),
580→      });
581→
582→    case 'OBJECT_DELETE': {
583→      const object = getManagedObject(state.project, action.objectId);
584→      if (!object) return state;
585→
586→      const strippedProject = removeObjectArtifacts(state.project, object.id);
587→      return applyUpdate(state, {
588→        ...strippedProject,
589→        updatedAt: new Date().toISOString(),
590→        objects: (strippedProject.objects || []).filter((entry) => entry.id !== object.id),
591→      });
592→    }
593→
594→    case 'OBJECT_MOVE': {
595→      const object = getManagedObject(state.project, action.objectId);
596→      if (!object) return state;
597→
598→      const partIds = new Set(
599→        state.project.parts.filter((part) => part.objectId === object.id).map((part) => part.id)
600→      );
601→
602→      let nextProject = {
603→        ...state.project,
604→        updatedAt: new Date().toISOString(),
605→        objects: state.project.objects.map((entry) => (
606→          entry.id === object.id
607→            ? {
608→                ...entry,
609→                origin: {
610→                  x: entry.origin.x + (action.delta.dx || 0),
611→                  y: entry.origin.y + (action.delta.dy || 0),
612→                  z: entry.origin.z + (action.delta.dz || 0),
613→                },
614→                updatedAt: new Date().toISOString(),
615→              }
616→            : entry
617→        )),
618→        parts: state.project.parts.map((part) => {
619→          if (!partIds.has(part.id) || part.type === 'dimension') return part;
620→          return sanitizePart({
621→            ...part,
622→            position: {
623→              x: part.position.x + (action.delta.dx || 0),
624→              y: part.position.y + (action.delta.dy || 0),
625→              z: part.position.z + (action.delta.dz || 0),
626→            },
627→          });
628→        }),
629→      };
630→      nextProject = applyConstraints(nextProject);
631→      for (const partId of partIds) {
632→        nextProject = updateBoundDimensions(nextProject, partId);
633→      }
634→      return applyUpdate(state, nextProject);
635→    }
636→
637→    case 'OBJECT_DETACH': {
638→      const object = getManagedObject(state.project, action.objectId);
639→      if (!object) return state;
640→      return applyUpdate(state, {
641→        ...detachManagedObject(state.project, object.id),
642→        updatedAt: new Date().toISOString(),
643→      });
644→    }
645→
646→    case 'CONSTRAINT_ADD': {
647→      const constraints = [...(state.project.constraints || []), action.constraint];
648→      let nextProject = {
649→        ...state.project,
650→        updatedAt: new Date().toISOString(),
651→        constraints,
652→      };
653→      nextProject = applyConstraints(nextProject);
654→      return applyUpdate(state, nextProject);
655→    }
656→
657→    case 'CONSTRAINT_UPDATE': {
658→      const constraints = (state.project.constraints || []).map((constraint) => (
659→        constraint.id === action.constraint.id ? { ...constraint, ...action.constraint } : constraint
660→      ));
661→      let nextProject = {
662→        ...state.project,
663→        updatedAt: new Date().toISOString(),
664→        constraints,
665→      };
666→      nextProject = applyConstraints(nextProject);
667→      return applyUpdate(state, nextProject);
