741→          sheet.id === action.sheetId
742→            ? { ...sheet, viewports: [...(sheet.viewports || []), action.viewport] }
743→            : sheet
744→        )),
745→      });
746→    }
747→
748→    case 'SKETCH_SHEET_VIEWPORT_UPDATE':
749→      return applyUpdate(state, {
750→        ...state.project,
751→        updatedAt: new Date().toISOString(),
752→        sheets: (state.project.sheets || []).map((sheet) => (
753→          sheet.id === action.sheetId
754→            ? {
755→                ...sheet,
756→                viewports: (sheet.viewports || []).map((viewport) => (
757→                  viewport.id === action.viewport.id ? { ...viewport, ...action.viewport } : viewport
758→                )),
759→              }
760→            : sheet
761→        )),
762→      });
763→
764→    case 'SKETCH_SHEET_VIEWPORT_DELETE':
765→      return applyUpdate(state, {
766→        ...state.project,
767→        updatedAt: new Date().toISOString(),
768→        sheets: (state.project.sheets || []).map((sheet) => (
769→          sheet.id === action.sheetId
770→            ? { ...sheet, viewports: (sheet.viewports || []).filter((viewport) => viewport.id !== action.viewportId) }
771→            : sheet
772→        )),
773→      });
774→
775→    case 'TEMPLATE_GENERATE': {
776→      const generated = generateObjectFromTemplate(action.templateType, action.params, {
777→        objectId: action.objectId,
778→        name: action.name,
779→        origin: action.origin,
780→      });
781→      return applyUpdate(state, {
782→        ...addGeneratedObject(state.project, generated),
783→        updatedAt: new Date().toISOString(),
784→      });
785→    }
786→
787→    case 'TEMPLATE_REGENERATE': {
788→      const object = action.objectId
789→        ? getManagedObject(state.project, action.objectId)
790→        : getManagedObjectForAssembly(state.project, action.assemblyId);
791→      if (!object || !object.templateType) return state;
792→
793→      const nextProject = rebuildManagedObject(state.project, object, action.params);
794→      return applyUpdate(state, {
795→        ...nextProject,
796→        updatedAt: new Date().toISOString(),
797→      });
798→    }
799→
800→    case 'TEMPLATE_DETACH': {
801→      const object = action.objectId
802→        ? getManagedObject(state.project, action.objectId)
803→        : getManagedObjectForAssembly(state.project, action.assemblyId);
804→      if (!object) return state;
805→      return sketchReducer(state, { type: 'OBJECT_DETACH', objectId: object.id });
806→    }
807→
808→    case 'UNDO': {
809→      if (state.history.length === 0) return state;
810→      const previous = state.history[state.history.length - 1];
811→      return {
812→        ...state,
813→        project: previous,
814→        history: state.history.slice(0, -1),
815→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
816→        isDirty: snapshotSketch(previous) !== state.savedSnapshot,
817→      };
818→    }
819→
820→    case 'REDO': {
821→      if (state.future.length === 0) return state;
822→      const next = state.future[0];
823→      return {
824→        ...state,
825→        project: next,
826→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
827→        future: state.future.slice(1),
828→        isDirty: snapshotSketch(next) !== state.savedSnapshot,
829→      };
830→    }
831→
832→    case 'MARK_SAVED':
833→      return {
834→        ...state,
835→        isDirty: false,
836→        savedSnapshot: snapshotSketch(state.project),
837→      };
838→
839→    default:
840→      return state;
841→  }
842→}
843→
844→function createInitialState(project) {
845→  return {
846→    project,
847→    isDirty: false,
848→    savedSnapshot: snapshotSketch(project),
849→    history: [],
850→    future: [],
851→  };
852→}
853→
854→export function SketchProvider({ children, initialProject }) {
855→  const [state, dispatch] = useReducer(
856→    sketchReducer,
857→    normalizeSketchObjects(initialProject || createSketchProject()),
858→    createInitialState
859→  );
860→
861→  return (
862→    <SketchContext.Provider value={{ state, dispatch }}>
863→      {children}
864→    </SketchContext.Provider>
865→  );
866→}
867→
868→export function useSketch() {
869→  const ctx = useContext(SketchContext);
870→  if (!ctx) throw new Error('useSketch must be used within SketchProvider');
871→  const { state, dispatch } = ctx;
872→
873→  const getPart = useCallback(
874→    (partId) => state.project.parts.find((part) => part.id === partId) || null,
875→    [state.project.parts]
876→  );
877→
878→  const getAssembly = useCallback(
879→    (assemblyId) => state.project.assemblies.find((assembly) => assembly.id === assemblyId) || null,
880→    [state.project.assemblies]
881→  );
882→
883→  const getObject = useCallback(
884→    (objectId) => (state.project.objects || []).find((object) => object.id === objectId) || null,
885→    [state.project.objects]
886→  );
887→
888→  const getPartsForAssembly = useCallback(
889→    (assemblyId) => state.project.parts.filter((part) => part.assemblyId === assemblyId),
890→    [state.project.parts]
891→  );
892→
893→  const getChildParts = useCallback(
894→    (parentId) => state.project.parts.filter((part) => part.parentId === parentId),
895→    [state.project.parts]
896→  );
897→
898→  const getAssembliesForObject = useCallback(
899→    (objectId) => state.project.assemblies.filter((assembly) => assembly.objectId === objectId),
900→    [state.project.assemblies]
901→  );
902→
903→  return {
904→    project: state.project,
905→    isDirty: state.isDirty,
906→    canUndo: state.history.length > 0,
907→    canRedo: state.future.length > 0,
908→    dispatch,
909→    getPart,
910→    getAssembly,
911→    getObject,
912→    getPartsForAssembly,
913→    getChildParts,
914→    getAssembliesForObject,
915→  };
916→}
