140→function DimensionFields({ part, onUpdate, dispatch, project }) {
141→  const measurement = Math.round(
142→    Math.sqrt(
143→      Math.pow((part.endPoint?.x || 0) - (part.startPoint?.x || 0), 2) +
144→      Math.pow((part.endPoint?.y || 0) - (part.startPoint?.y || 0), 2) +
145→      Math.pow((part.endPoint?.z || 0) - (part.startPoint?.z || 0), 2)
146→    )
147→  );
148→
149→  const handleBoundValueChange = (newVal) => {
150→    if (!part.boundPartId || !part.boundProperty) return;
151→    const boundPart = project.parts.find((p) => p.id === part.boundPartId);
152→    if (!boundPart) return;
153→    const result = applyDimensionValueToPart(part, newVal, boundPart);
154→    if (result) {
155→      dispatch({ type: 'PART_UPDATE', part: { id: result.partId, ...result.changes } });
156→    }
157→  };
158→
159→  const bindableParts = project.parts.filter((p) => p.type !== 'dimension');
160→
161→  const BINDABLE_PROPS = {
162→    panel: ['width', 'depth', 'thickness'],
163→    leg: ['width', 'depth', 'height'],
164→    frame: ['width', 'height', 'length'],
165→    cutout: ['width', 'height', 'depth'],
166→    hole: ['diameter', 'depth'],
167→  };
168→
169→  const handleBind = (partId, property) => {
170→    const target = project.parts.find((p) => p.id === partId);
171→    if (!target) return;
172→    const updated = bindDimensionToPart(part, target, property);
173→    dispatch({ type: 'PART_UPDATE', part: { id: part.id, ...updated } });
174→  };
175→
176→  return (
177→    <>
178→      {part.boundPartId ? (
179→        <NumberInput
180→          label="Value"
181→          value={measurement}
182→          suffix="mm"
183→          onChange={handleBoundValueChange}
184→        />
185→      ) : (
186→        <NumberInput label="Measured" value={measurement} readOnly suffix="mm" onChange={() => {}} />
187→      )}
188→      <NumberInput label="Offset" value={part.offset || 200} onChange={(v) => onUpdate({ offset: v })} />
189→      <TextInput label="Text Override" value={part.textOverride || ''} onChange={(v) => onUpdate({ textOverride: v || null })} />
190→      {part.boundPartId && (
191→        <div className={styles.field}>
192→          <span className={styles.fieldLabel}>Bound to</span>
193→          <span className={styles.typeBadge}>{part.boundProperty || 'part'}</span>
194→        </div>
195→      )}
196→      {!part.boundPartId && bindableParts.length > 0 && (
197→        <BindDimensionUI parts={bindableParts} bindableProps={BINDABLE_PROPS} onBind={handleBind} />
198→      )}
199→    </>
200→  );
201→}
