572→  const template = assembly.templateType ? getTemplate(assembly.templateType) : null;
573→  const object = assembly.objectId
574→    ? (project.objects || []).find((entry) => entry.id === assembly.objectId && entry.editingPolicy === 'parametric')
575→    : null;
576→  const [pendingParams, setPendingParams] = useState(
577→    assembly.templateParams ? { ...assembly.templateParams } : {}
578→  );
579→
580→  const partCount = assembly.partIds.length;
581→
582→  const handleNameChange = (name) => {
583→    dispatch({ type: 'ASSEMBLY_UPDATE', assembly: { id: assembly.id, name } });
584→  };
585→
586→  const handleParamChange = (key, value) => {
587→    setPendingParams((prev) => ({ ...prev, [key]: value }));
588→  };
589→
590→  const handleApply = () => {
591→    dispatch({ type: 'TEMPLATE_REGENERATE', assemblyId: assembly.id, params: pendingParams });
592→  };
593→
594→  const handleDetach = () => {
595→    dispatch({ type: 'TEMPLATE_DETACH', assemblyId: assembly.id });
596→  };
597→
598→  return (
599→    <div className={styles.panel}>
600→      <div className={styles.header}>Assembly</div>
601→      <div className={styles.content}>
602→        {object ? (
603→          <div className={styles.field}>
604→            <span className={styles.fieldLabel}>Name</span>
605→            <span style={{ fontSize: '11px', color: 'var(--color-text-secondary)' }}>{assembly.name}</span>
606→          </div>
607→        ) : (
608→          <TextInput label="Name" value={assembly.name} onChange={handleNameChange} />
609→        )}
610→
611→        {object && (
612→          <>
613→            <div className={styles.field}>
614→              <span className={styles.fieldLabel}>Managed by</span>
615→              <span className={styles.typeBadge}>{object.name}</span>
616→            </div>
617→            <div className={styles.field}>
618→              <span className={styles.fieldLabel}>Editing</span>
619→              <span style={{ fontSize: '11px', color: 'var(--color-text-secondary)' }}>
620→                This assembly is generated from object parameters.
621→              </span>
622→            </div>
623→          </>
624→        )}
625→
626→        {template && !object ? (
627→          <>
628→            <div className={styles.field}>
629→              <span className={styles.fieldLabel}>Template</span>
630→              <span className={styles.typeBadge}>{template.label}</span>
631→            </div>
632→
633→            <div className={styles.field}>
634→              <span className={styles.fieldLabel}>Parts</span>
635→              <span style={{ fontSize: '11px', color: 'var(--color-text-secondary)' }}>{partCount}</span>
636→            </div>
637→
638→            <div className={styles.fieldGroup}>
639→              <span className={styles.groupTitle}>Parameters</span>
640→              <TemplateParamsForm
641→                parameters={template.parameters}
642→                values={pendingParams}
643→                onChange={handleParamChange}
644→              />
645→            </div>
646→
647→            <button className={styles.duplicateBtn} onClick={handleApply}>
648→              Apply Changes
649→            </button>
650→            <button className={styles.duplicateBtn} onClick={handleDetach} style={{ color: '#888' }}>
651→              Detach Template
652→            </button>
653→          </>
654→        ) : (
655→          <>
656→            <div className={styles.field}>
657→              <span className={styles.fieldLabel}>Category</span>
658→              <span style={{ fontSize: '11px', color: 'var(--color-text-secondary)' }}>{assembly.category || 'general'}</span>
659→            </div>
660→            <div className={styles.field}>
661→              <span className={styles.fieldLabel}>Parts</span>
662→              <span style={{ fontSize: '11px', color: 'var(--color-text-secondary)' }}>{partCount}</span>
663→            </div>
664→            {assembly.description && (
665→              <div className={styles.field}>
666→                <span className={styles.fieldLabel}>Description</span>
667→                <span style={{ fontSize: '11px', color: 'var(--color-text-secondary)' }}>{assembly.description}</span>
668→              </div>
669→            )}
670→          </>
671→        )}
672→      </div>
673→    </div>
674→  );
675→}
