  9→export function createPreviewViewport(container) {
 10→  const materialPalette = createMaterialPalette();
 11→  const scene = new THREE.Scene();
 12→  scene.background = null;
 13→  const raycaster = new THREE.Raycaster();
 14→  const timer = new THREE.Timer();
 15→  timer.connect(document);
 16→
 17→  const camera = new THREE.PerspectiveCamera(42, 1, 10, 100000);
 18→  const renderer = new THREE.WebGLRenderer({
 19→    antialias: true,
 20→    alpha: true,
 21→    powerPreference: 'high-performance',
 22→  });
 23→  renderer.outputColorSpace = THREE.SRGBColorSpace;
 24→  renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));
 25→  renderer.setSize(container.clientWidth || 1, container.clientHeight || 1, false);
 26→  renderer.domElement.style.width = '100%';
 27→  renderer.domElement.style.height = '100%';
 28→  renderer.domElement.style.display = 'block';
 29→  container.appendChild(renderer.domElement);
 30→
 31→  const inspectNavigation = createInspectNavigation({
 32→    camera,
 33→    domElement: renderer.domElement,
 34→  });
 35→
 36→  scene.add(new THREE.AmbientLight(0xffffff, 0.72));
 37→  scene.add(new THREE.HemisphereLight(0xdde7f4, 0xe6ded0, 0.7));
 38→  const keyLight = new THREE.DirectionalLight(0xffffff, 1.05);
 39→  keyLight.position.set(3500, 5000, 2000);
 40→  scene.add(keyLight);
 41→
 42→  let animationFrame = 0;
 43→  let worldRoot = null;
 44→  let gridHelper = null;
 45→  let currentBounds = null;
 46→  let pickHandler = null;
 47→  let pickContext = { activeFloorId: null };
 48→  let pointerDown = null;
 49→  let navigationMode = 'inspect';
 50→  let walkUiHandler = null;
 51→  let walkExitHandler = null;
 52→  let compassHeadingHandler = null;
 53→  let inspectState = null;
 54→  let activeFloorContext = {
 55→    floorId: null,
 56→    spawn: null,
 57→  };
 58→  const walkPoseByFloorId = new Map();
 59→  const forwardVector = new THREE.Vector3();
 60→  const horizontalForward = new THREE.Vector3();
 61→  let lastCompassHeading = 0;
 62→  const walkNavigation = createWalkNavigation({
 63→    camera,
 64→    domElement: renderer.domElement,
 65→    onStateChange: () => {
 66→      emitWalkUiState();
 67→    },
 68→    onExitRequested: () => {
 69→      setNavigationMode('inspect');
 70→      walkExitHandler?.();
 71→    },
 72→  });
 73→
 74→  const emitWalkUiState = () => {
 75→    walkUiHandler?.({
 76→      navigationMode,
 77→      isLocked: navigationMode === 'walk' && walkNavigation.isLocked(),
 78→      canLock: navigationMode === 'walk',
 79→    });
 80→  };
 81→
 82→  const emitCompassHeading = () => {
 83→    if (!compassHeadingHandler) return;
 84→
 85→    camera.getWorldDirection(forwardVector);
 86→    horizontalForward.set(forwardVector.x, 0, forwardVector.z);
 87→    if (horizontalForward.lengthSq() > 1e-6) {
 88→      horizontalForward.normalize();
 89→      lastCompassHeading = THREE.MathUtils.radToDeg(
 90→        Math.atan2(horizontalForward.x, -horizontalForward.z)
 91→      );
 92→    }
 93→
 94→    compassHeadingHandler(lastCompassHeading);
 95→  };
 96→
 97→  const saveCurrentWalkPose = () => {
 98→    if (!activeFloorContext.floorId) return;
 99→    walkPoseByFloorId.set(activeFloorContext.floorId, walkNavigation.capturePose());
100→  };
101→
102→  const restoreWalkPose = ({ forceSpawn = false } = {}) => {
103→    if (!activeFloorContext.floorId) return;
104→
105→    const rememberedPose = !forceSpawn
106→      ? walkPoseByFloorId.get(activeFloorContext.floorId)
107→      : null;
108→
109→    if (rememberedPose) {
110→      walkNavigation.restorePose(rememberedPose);
111→      return;
112→    }
113→
114→    const spawn = activeFloorContext.spawn;
115→    if (!spawn?.position || !spawn.lookAt) return;
116→
117→    walkNavigation.restorePose({
118→      position: [spawn.position.x, spawn.position.y, spawn.position.z],
119→      lookAt: [spawn.lookAt.x, spawn.lookAt.y, spawn.lookAt.z],
120→    });
121→  };
122→
123→  const setNavigationMode = (nextMode = 'inspect') => {
124→    const resolvedMode = nextMode === 'walk' ? 'walk' : 'inspect';
125→    if (navigationMode === resolvedMode) {
126→      emitWalkUiState();
127→      return;
128→    }
129→
130→    if (navigationMode === 'inspect') {
131→      inspectState = inspectNavigation.captureState();
132→    }
133→
134→    if (navigationMode === 'walk') {
135→      saveCurrentWalkPose();
136→    }
137→
138→    navigationMode = resolvedMode;
139→    inspectNavigation.setEnabled(navigationMode === 'inspect');
140→    walkNavigation.setEnabled(navigationMode === 'walk');
141→
142→    if (navigationMode === 'inspect') {
143→      // Derive inspect state from walk camera so the view doesn't jump
144→      const forward = new THREE.Vector3();
145→      camera.getWorldDirection(forward);
146→      const orbitTarget = camera.position.clone().add(forward.multiplyScalar(3000));
147→      const derived = {
148→        position: camera.position.toArray(),
149→        target: orbitTarget.toArray(),
150→      };
151→      if (!inspectNavigation.restoreState(derived)) {
152→        inspectNavigation.resetView();
153→      }
154→    } else {
155→      restoreWalkPose();
156→    }
157→
158→    emitWalkUiState();
159→  };
160→
161→  const renderFrame = (timestamp) => {
162→    timer.update(timestamp);
163→    const deltaSeconds = Math.min(timer.getDelta(), 0.1);
164→    if (navigationMode === 'inspect') {
165→      inspectNavigation.update(deltaSeconds);
166→    } else {
167→      walkNavigation.update(deltaSeconds);
168→    }
169→    emitCompassHeading();
170→    renderer.render(scene, camera);
171→    animationFrame = window.requestAnimationFrame(renderFrame);
172→  };
173→
174→  const resize = () => {
175→    const width = container.clientWidth || 1;
176→    const height = container.clientHeight || 1;
177→    camera.aspect = width / height;
178→    camera.updateProjectionMatrix();
179→    renderer.setSize(width, height, false);
180→  };
181→
182→  const resolvePickTarget = (object) => {
183→    let current = object;
184→    while (current) {
185→      if (current.userData?.previewTarget) {
186→        return current.userData.previewTarget;
187→      }
188→      current = current.parent;
189→    }
190→    return null;
191→  };
192→
193→  const pickObjectAt = (clientX, clientY) => {
194→    if (navigationMode !== 'inspect') return;
195→    if (!worldRoot || !pickHandler) return;
196→
197→    const rect = renderer.domElement.getBoundingClientRect();
198→    if (!rect.width || !rect.height) return;
199→
200→    const pointer = new THREE.Vector2(
201→      ((clientX - rect.left) / rect.width) * 2 - 1,
202→      -(((clientY - rect.top) / rect.height) * 2 - 1)
203→    );
204→
205→    raycaster.setFromCamera(pointer, camera);
206→    const hits = raycaster.intersectObject(worldRoot, true);
207→    const seenTargets = new Set();
208→    const targets = [];
209→
210→    for (const hit of hits) {
211→      const target = resolvePickTarget(hit.object);
212→      if (!target) continue;
213→
214→      const key = `${target.floorId || ''}:${target.kind}:${target.sourceId}`;
215→      if (seenTargets.has(key)) continue;
216→      seenTargets.add(key);
217→      targets.push(target);
218→    }
219→
220→    if (!targets.length) {
221→      pickHandler(null);
222→      return;
223→    }
224→
225→    const preferredTarget = pickContext.activeFloorId
226→      ? targets.find((target) => target.floorId === pickContext.activeFloorId) || null
227→      : null;
228→
229→    pickHandler(preferredTarget || targets[0]);
230→  };
231→
232→  const handlePointerDown = (event) => {
233→    if (navigationMode !== 'inspect') {
234→      pointerDown = null;
235→      return;
236→    }
237→
238→    if (event.button !== 0) {
239→      pointerDown = null;
240→      return;
241→    }
242→
243→    pointerDown = {
244→      x: event.clientX,
245→      y: event.clientY,
246→    };
247→  };
248→
249→  const handlePointerCancel = () => {
250→    pointerDown = null;
251→  };
252→
253→  const handlePointerUp = (event) => {
254→    if (navigationMode !== 'inspect') {
255→      pointerDown = null;
256→      return;
257→    }
258→
259→    if (event.button !== 0 || !pointerDown) {
260→      pointerDown = null;
261→      return;
262→    }
263→
264→    const dx = event.clientX - pointerDown.x;
265→    const dy = event.clientY - pointerDown.y;
266→    pointerDown = null;
267→
268→    if (Math.hypot(dx, dy) > CLICK_DISTANCE_THRESHOLD) {
269→      return;
270→    }
271→
272→    pickObjectAt(event.clientX, event.clientY);
273→  };
274→
275→  renderer.domElement.addEventListener('pointerdown', handlePointerDown);
276→  renderer.domElement.addEventListener('pointerup', handlePointerUp);
277→  renderer.domElement.addEventListener('pointercancel', handlePointerCancel);
278→  renderer.domElement.addEventListener('pointerleave', handlePointerCancel);
279→
280→  animationFrame = window.requestAnimationFrame(renderFrame);
281→
282→  return {
283→    setWorld(nextRoot, bounds, groundLevel = 0) {
284→      const hadWorld = !!worldRoot;
285→      const walkPose = navigationMode === 'walk' ? walkNavigation.capturePose() : null;
286→
287→      if (worldRoot) {
288→        scene.remove(worldRoot);
289→        disposeScene(worldRoot, { disposeMaterials: true });
290→      }
291→
292→      if (gridHelper) {
293→        scene.remove(gridHelper);
294→        gridHelper.geometry?.dispose?.();
295→        gridHelper.material?.dispose?.();
296→      }
297→
298→      worldRoot = nextRoot;
299→      currentBounds = descriptorBoundsToWorldBox(bounds);
300→      inspectNavigation.setBounds(currentBounds);
301→      gridHelper = createGrid(bounds, groundLevel);
302→      scene.add(gridHelper);
303→      scene.add(worldRoot);
304→      if (!hadWorld && navigationMode === 'inspect') {
305→        inspectNavigation.resetView();
306→      }
307→
308→      if (walkPose) {
309→        walkNavigation.restorePose(walkPose);
310→      }
311→    },
312→    resetView() {
313→      if (navigationMode === 'walk') {
314→        if (activeFloorContext.floorId) {
315→          walkPoseByFloorId.delete(activeFloorContext.floorId);
316→        }
317→        restoreWalkPose({ forceSpawn: true });
318→        return;
319→      }
320→      inspectNavigation.resetView();
321→    },
322→    fit() {
323→      inspectNavigation.resetView();
324→    },
325→    setProjectionPreset(presetName) {
326→      inspectNavigation.setProjectionPreset(presetName);
327→    },
328→    setPickHandler(handler) {
329→      pickHandler = typeof handler === 'function' ? handler : null;
330→    },
331→    setPickContext(nextContext = {}) {
332→      pickContext = {
333→        ...pickContext,
334→        ...nextContext,
335→      };
336→    },
337→    setNavigationMode,
338→    setActiveFloorContext(nextContext = {}) {
339→      const previousFloorId = activeFloorContext.floorId;
340→      const nextFloorId = nextContext.floorId ?? activeFloorContext.floorId;
341→      const floorChanged = previousFloorId !== nextFloorId;
342→
343→      if (navigationMode === 'walk' && floorChanged && previousFloorId) {
344→        saveCurrentWalkPose();
345→      }
346→
347→      activeFloorContext = {
348→        ...activeFloorContext,
349→        ...nextContext,
350→      };
351→
352→      if (navigationMode === 'walk' && floorChanged) {
353→        restoreWalkPose();
354→      }
355→    },
356→    setWalkUiHandler(handler) {
357→      walkUiHandler = typeof handler === 'function' ? handler : null;
358→      emitWalkUiState();
359→    },
360→    setWalkExitHandler(handler) {
361→      walkExitHandler = typeof handler === 'function' ? handler : null;
362→    },
363→    setCompassHeadingHandler(handler) {
364→      compassHeadingHandler = typeof handler === 'function' ? handler : null;
365→      emitCompassHeading();
366→    },
367→    resize,
368→    dispose() {
369→      window.cancelAnimationFrame(animationFrame);
370→      inspectNavigation.dispose();
371→      walkNavigation.dispose();
372→      renderer.domElement.removeEventListener('pointerdown', handlePointerDown);
373→      renderer.domElement.removeEventListener('pointerup', handlePointerUp);
374→      renderer.domElement.removeEventListener('pointercancel', handlePointerCancel);
375→      renderer.domElement.removeEventListener('pointerleave', handlePointerCancel);
376→
377→      if (worldRoot) {
378→        scene.remove(worldRoot);
379→        disposeScene(worldRoot, { disposeMaterials: true });
380→      }
381→
382→      if (gridHelper) {
383→        scene.remove(gridHelper);
384→        gridHelper.geometry?.dispose?.();
385→        gridHelper.material?.dispose?.();
386→      }
387→
388→      disposeMaterialPalette(materialPalette);
389→      timer.dispose();
390→      renderer.dispose();
391→      renderer.domElement.remove();
392→    },
393→    materialPalette,
394→  };
395→}
