 1→import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls.js';
 2→import { DEFAULT_PRESET_NAME, PRESETS } from './previewConfig';
 3→import { fitCameraToBox } from './previewCameraMath';
 4→
 5→export function createInspectNavigation({ camera, domElement }) {
 6→  const controls = new OrbitControls(camera, domElement);
 7→  controls.enableDamping = true;
 8→  controls.dampingFactor = 0.08;
 9→  controls.screenSpacePanning = true;
10→  controls.minDistance = 400;
11→  controls.maxDistance = 150000;
12→  controls.maxPolarAngle = Math.PI * 0.495;
13→
14→  let currentBounds = null;
15→  let currentPreset = DEFAULT_PRESET_NAME;
16→
17→  return {
18→    update() {
19→      controls.update();
20→    },
21→    setBounds(bounds) {
22→      currentBounds = bounds ? bounds.clone() : null;
23→    },
24→    setEnabled(enabled) {
25→      controls.enabled = enabled;
26→    },
27→    resetView() {
28→      if (!currentBounds) return;
29→      fitCameraToBox(camera, controls, currentBounds, currentPreset);
30→    },
31→    setProjectionPreset(presetName = DEFAULT_PRESET_NAME) {
32→      currentPreset = presetName in PRESETS ? presetName : DEFAULT_PRESET_NAME;
33→      if (!currentBounds) return;
34→      fitCameraToBox(camera, controls, currentBounds, currentPreset);
35→    },
36→    captureState() {
37→      return {
38→        position: camera.position.toArray(),
39→        target: controls.target.toArray(),
40→      };
41→    },
42→    restoreState(state) {
43→      if (!state?.position || !state?.target) return false;
44→      camera.position.fromArray(state.position);
45→      controls.target.fromArray(state.target);
46→      camera.updateProjectionMatrix();
47→      controls.update();
48→      return true;
49→    },
50→    dispose() {
51→      controls.dispose();
52→    },
53→  };
54→}
