  3→const SELECTED_SURFACE_COLOR = new THREE.Color(0xcdeedd);
  4→const SELECTED_EMISSIVE_COLOR = new THREE.Color(0x0f8f74);
  5→const SELECTED_OUTLINE_COLOR = new THREE.Color(0x0f8f74);
  6→
  7→function planPointToWorld(point, elevation = 0) {
  8→  return new THREE.Vector3(point.x, elevation, point.y);
  9→}
 10→
 11→function planAngleToWorldRotation(angle = 0) {
 12→  return -angle;
 13→}
 14→
 15→function createShape(outline, holes = []) {
 16→  const shape = new THREE.Shape();
 17→  outline.forEach((point, index) => {
 18→    if (index === 0) {
 19→      // Flip plan Y here so the rotated extrusion preserves the blueprint's handedness.
 20→      shape.moveTo(point.x, -point.y);
 21→      return;
 22→    }
 23→    shape.lineTo(point.x, -point.y);
 24→  });
 25→  shape.closePath();
 26→
 27→  holes.forEach((hole) => {
 28→    if (!hole?.length) return;
 29→    const path = new THREE.Path();
 30→    hole.forEach((point, index) => {
 31→      if (index === 0) {
 32→        path.moveTo(point.x, -point.y);
 33→        return;
 34→      }
 35→      path.lineTo(point.x, -point.y);
 36→    });
 37→    path.closePath();
 38→    shape.holes.push(path);
 39→  });
 40→
 41→  return shape;
 42→}
 43→
 44→function applySelectedSurfaceStyle(material) {
 45→  if (material.color) {
 46→    material.color.lerp(SELECTED_SURFACE_COLOR, 0.36);
 47→  }
 48→  if ('emissive' in material && material.emissive) {
 49→    material.emissive.copy(SELECTED_EMISSIVE_COLOR);
 50→    material.emissiveIntensity = material.transparent ? 0.12 : 0.22;
 51→  }
 52→  if (material.transparent) {
 53→    material.opacity = Math.min(0.82, Math.max(material.opacity ?? 1, 0.58));
 54→  }
 55→}
 56→
 57→function createMeshMaterial(materialPalette, materialKey, isSelected) {
 58→  const material = materialPalette[materialKey].clone();
 59→  if (isSelected) applySelectedSurfaceStyle(material);
 60→  return material;
 61→}
 62→
 63→function createOutlineMaterial(materialPalette, isSelected) {
 64→  const material = materialPalette.outline.clone();
 65→  if (isSelected) {
 66→    material.color.copy(SELECTED_OUTLINE_COLOR);
 67→    material.opacity = 1;
 68→  }
 69→  return material;
 70→}
 71→
 72→function addOutline(object3d, materialPalette, isSelected) {
 73→  if (!object3d.geometry) return;
 74→  const edges = new THREE.EdgesGeometry(object3d.geometry, 20);
 75→  const outline = new THREE.LineSegments(edges, createOutlineMaterial(materialPalette, isSelected));
 76→  object3d.add(outline);
 77→}
