 97→function createRoofMeshObject(descriptor, materialPalette, isSelected) {
 98→  const positions = [];
 99→
100→  function pushVertex(point, elevation) {
101→    positions.push(point.x, elevation, point.y);
102→  }
103→
104→  function pushTriangle(a, b, c, surface) {
105→    pushVertex(a, surface === 'top' ? a.topElevation : a.bottomElevation);
106→    pushVertex(b, surface === 'top' ? b.topElevation : b.bottomElevation);
107→    pushVertex(c, surface === 'top' ? c.topElevation : c.bottomElevation);
108→  }
109→
110→  function pushQuad(a, b) {
111→    pushVertex(a, a.topElevation);
112→    pushVertex(b, b.topElevation);
113→    pushVertex(b, b.bottomElevation);
114→
115→    pushVertex(a, a.topElevation);
116→    pushVertex(b, b.bottomElevation);
117→    pushVertex(a, a.bottomElevation);
118→  }
119→
120→  for (const surface of descriptor.surfaces || []) {
121→    const outline = surface.outline || [];
122→    if (outline.length < 3) continue;
123→
124→    const contour = outline.map((point) => new THREE.Vector2(point.x, -point.y));
125→    const faces = THREE.ShapeUtils.triangulateShape(contour, []);
126→
127→    for (const face of faces) {
128→      const a = outline[face[0]];
129→      const b = outline[face[1]];
130→      const c = outline[face[2]];
131→      pushTriangle(a, b, c, 'top');
132→      pushTriangle(c, b, a, 'bottom');
133→    }
134→  }
135→
136→  const outerBoundary = descriptor.outerBoundary || [];
137→  for (let index = 0; index < outerBoundary.length; index += 1) {
138→    const start = outerBoundary[index];
139→    const end = outerBoundary[(index + 1) % outerBoundary.length];
140→    pushQuad(start, end);
141→  }
142→
143→  const geometry = new THREE.BufferGeometry();
144→  geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
145→  geometry.computeVertexNormals();
146→
147→  const mesh = new THREE.Mesh(geometry, createMeshMaterial(materialPalette, descriptor.materialKey, isSelected));
148→  mesh.castShadow = true;
149→  mesh.receiveShadow = true;
150→  addOutline(mesh, materialPalette, isSelected);
151→  return mesh;
152→}
