154→function createBoxObject(descriptor, materialPalette, isSelected) {
155→  const geometry = new THREE.BoxGeometry(
156→    Math.max(descriptor.size.x, 1),
157→    Math.max(descriptor.size.y, 1),
158→    Math.max(descriptor.size.z, 1)
159→  );
160→  const mesh = new THREE.Mesh(geometry, createMeshMaterial(materialPalette, descriptor.materialKey, isSelected));
161→  const center = planPointToWorld(
162→    descriptor.center,
163→    descriptor.baseElevation + descriptor.size.y / 2
164→  );
165→  mesh.position.copy(center);
166→  mesh.rotation.y = planAngleToWorldRotation(descriptor.rotation);
167→  mesh.castShadow = true;
168→  mesh.receiveShadow = true;
169→  addOutline(mesh, materialPalette, isSelected);
170→  return mesh;
171→}
