496→const FIXTURE_BUILDERS = {
497→  kitchenTop: buildKitchenTopFixture,
498→  toilet: buildToiletFixture,
499→  lavatory: buildLavatoryFixture,
500→  table: buildTableFixture,
501→  tv: buildTvFixture,
502→  sofa: buildSofaFixture,
503→  bed: buildBedFixture,
