 1→import * as THREE from 'three';
 2→import { DEFAULT_PRESET_NAME, PRESETS } from './previewConfig';
 3→
 4→export function descriptorBoundsToWorldBox(bounds) {
 5→  return new THREE.Box3(
 6→    new THREE.Vector3(bounds.minX, bounds.minElevation, bounds.minY),
 7→    new THREE.Vector3(bounds.maxX, bounds.maxElevation, bounds.maxY)
 8→  );
 9→}
10→
11→export function createGrid(bounds, groundLevel) {
12→  const size = Math.max(
13→    bounds.maxX - bounds.minX,
14→    bounds.maxY - bounds.minY,
15→    4000
16→  );
17→  const normalizedSize = Math.ceil(size / 1000) * 1000;
18→  const divisions = Math.max(8, Math.round(normalizedSize / 500));
19→  const grid = new THREE.GridHelper(normalizedSize, divisions, 0x8fa1b4, 0xc7d1db);
20→  grid.position.y = groundLevel;
21→  grid.material.transparent = true;
22→  grid.material.opacity = 0.45;
23→  return grid;
24→}
25→
26→export function fitCameraToBox(camera, controls, box, presetName = DEFAULT_PRESET_NAME) {
27→  const preset = PRESETS[presetName] || PRESETS[DEFAULT_PRESET_NAME];
28→  const direction = preset.clone().normalize();
29→  const size = box.getSize(new THREE.Vector3());
30→  const center = box.getCenter(new THREE.Vector3());
31→  const radius = Math.max(size.length() / 2, 1200);
32→  const halfFovY = THREE.MathUtils.degToRad(camera.fov / 2);
33→  const halfFovX = Math.atan(Math.tan(halfFovY) * camera.aspect);
34→  const distanceByHeight = Math.max(size.y, size.z) / (2 * Math.tan(halfFovY));
35→  const distanceByWidth = Math.max(size.x, size.z) / (2 * Math.tan(halfFovX));
36→  const distance = Math.max(distanceByHeight, distanceByWidth, radius * 1.4) * 1.15;
37→
38→  controls.target.copy(center);
39→  camera.position.copy(center.clone().add(direction.multiplyScalar(distance)));
40→  camera.near = Math.max(10, distance / 200);
41→  camera.far = distance * 10;
42→  camera.updateProjectionMatrix();
43→  controls.update();
44→}
