 881→        objectId: action.objectId,
 882→        name: action.name,
 883→        origin: action.origin,
 884→      });
 885→      return applyUpdate(state, {
 886→        ...addGeneratedObject(state.project, generated),
 887→        updatedAt: new Date().toISOString(),
 888→      });
 889→    }
 890→
 891→    case 'TEMPLATE_REGENERATE': {
 892→      const object = action.objectId
 893→        ? getManagedObject(state.project, action.objectId)
 894→        : getManagedObjectForAssembly(state.project, action.assemblyId);
 895→      if (!object || !object.templateType) return state;
 896→
 897→      const nextProject = rebuildManagedObject(state.project, object, action.params);
 898→      return applyUpdate(state, {
 899→        ...nextProject,
 900→        updatedAt: new Date().toISOString(),
 901→      });
 902→    }
 903→
 904→    case 'TEMPLATE_DETACH': {
 905→      const object = action.objectId
 906→        ? getManagedObject(state.project, action.objectId)
 907→        : getManagedObjectForAssembly(state.project, action.assemblyId);
 908→      if (!object) return state;
 909→      return sketchReducer(state, { type: 'OBJECT_DETACH', objectId: object.id });
 910→    }
 911→
 912→    case 'UNDO': {
 913→      if (state.history.length === 0) return state;
 914→      const previous = state.history[state.history.length - 1];
 915→      return {
 916→        ...state,
 917→        project: previous,
 918→        history: state.history.slice(0, -1),
 919→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
 920→        isDirty: snapshotSketch(previous) !== state.savedSnapshot,
 921→      };
 922→    }
 923→
 924→    case 'REDO': {
 925→      if (state.future.length === 0) return state;
 926→      const next = state.future[0];
 927→      return {
 928→        ...state,
 929→        project: next,
 930→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
 931→        future: state.future.slice(1),
 932→        isDirty: snapshotSketch(next) !== state.savedSnapshot,
 933→      };
 934→    }
 935→
 936→    case 'MARK_SAVED':
 937→      return {
 938→        ...state,
 939→        isDirty: false,
 940→        savedSnapshot: snapshotSketch(state.project),
 941→      };
 942→
 943→    default:
 944→      return state;
 945→  }
 946→}
 947→
 948→function createInitialState(project) {
 949→  return {
 950→    project,
 951→    isDirty: false,
 952→    savedSnapshot: snapshotSketch(project),
 953→    history: [],
 954→    future: [],
 955→  };
 956→}
