 958→export function SketchProvider({ children, initialProject }) {
 959→  const [state, dispatch] = useReducer(
 960→    sketchReducer,
 961→    normalizeSketchObjects(initialProject || createSketchProject()),
 962→    createInitialState
 963→  );
 964→
 965→  return (
 966→    <SketchContext.Provider value={{ state, dispatch }}>
 967→      {children}
 968→    </SketchContext.Provider>
 969→  );
 970→}
