126→export function createInitialSketchEditorState() {
127→  return {
128→    activeTool: SKETCH_TOOLS.SELECT,
129→    selectedId: null,
130→    selectedType: null,
131→    toolState: {},
132→    modelViewport: { panX: 400, panY: 300, zoom: DEFAULT_SKETCH_ZOOM },
133→    sheetViewport: { panX: 400, panY: 300, zoom: 2.0 },
134→    workspaceMode: 'model',
135→    activeSheetId: null,
136→    activeView: 'top',
137→    activeAssemblyId: null,
138→    showGrid: true,
139→    snapEnabled: true,
