 1→import { createAssembly } from './assemblyModels';
 2→import { createSketchObject } from './objectModels';
 3→import { getTemplate } from './templates/templateRegistry';
 4→import { materializePartDefinition } from './templates/templateHelpers';
 5→
 6→function applyOrigin(position = {}, origin = {}) {
 7→  return {
 8→    x: (Number(position.x) || 0) + (Number(origin.x) || 0),
 9→    y: (Number(position.y) || 0) + (Number(origin.y) || 0),
10→    z: (Number(position.z) || 0) + (Number(origin.z) || 0),
11→  };
12→}
13→
14→export function generateObjectFromTemplate(templateType, params, options = {}) {
15→  const template = getTemplate(templateType);
16→  if (!template?.buildDefinition) {
17→    throw new Error(`Template "${templateType}" does not define buildDefinition`);
18→  }
19→
20→  const definition = template.buildDefinition(params);
21→  const origin = options.origin || { x: 0, y: 0, z: 0 };
22→  const object = createSketchObject(options.name || definition.name, {
23→    id: options.objectId,
24→    description: definition.description || '',
25→    summary: definition.summary || '',
26→    category: templateType,
27→    templateType,
28→    templateParams: { ...params },
29→    dimensions: { ...definition.dimensions },
30→    origin,
31→    source: 'generated',
32→    editingPolicy: 'parametric',
33→    defaultName: definition.name,
34→  });
35→
36→  const assemblies = [];
37→  const parts = [];
38→
39→  function buildAssembly(definitionAssembly, parentAssemblyId = null, depth = 0) {
40→    const assembly = createAssembly(definitionAssembly.name, {
41→      objectId: object.id,
42→      parentAssemblyId,
43→      source: 'generated',
44→      role: definitionAssembly.key,
45→      category: templateType,
46→      description: definitionAssembly.description || '',
47→      sortIndex: definitionAssembly.sortIndex ?? depth,
48→      partIds: [],
49→      childAssemblyIds: [],
50→    });
51→
52→    assemblies.push(assembly);
53→    object.assemblyIds.push(assembly.id);
54→
55→    for (const child of definitionAssembly.children || []) {
56→      const childAssembly = buildAssembly(child, assembly.id, depth + 1);
57→      assembly.childAssemblyIds.push(childAssembly.id);
58→    }
59→
60→    let partIndex = 0;
61→    for (const partDefinition of definitionAssembly.parts || []) {
62→      const part = materializePartDefinition(partDefinition, {
63→        objectId: object.id,
64→        assemblyId: assembly.id,
65→        source: 'generated',
66→        locked: true,
67→        generatedRole: partDefinition.role,
68→        role: partDefinition.role,
69→        sortIndex: partIndex,
70→        position: applyOrigin(partDefinition.props?.position, origin),
71→      });
72→      assembly.partIds.push(part.id);
73→      object.partIds.push(part.id);
74→      parts.push(part);
75→      partIndex += 1;
76→    }
77→
78→    return assembly;
79→  }
80→
81→  for (const assemblyDefinition of definition.assemblies || []) {
82→    buildAssembly(assemblyDefinition);
83→  }
84→
85→  return {
86→    object,
87→    assemblies,
88→    parts,
89→    definition,
90→  };
91→}
