 3→function createLookAt(position) {
 4→  return {
 5→    x: position.x + DEFAULT_WALK_DIRECTION.x * WALK_LOOK_DISTANCE,
 6→    y: position.y,
 7→    z: position.z + DEFAULT_WALK_DIRECTION.z * WALK_LOOK_DISTANCE,
