11→export function resolveWalkFloorContext(sceneDescriptor, activeFloorId, eyeHeightOffset = WALK_EYE_HEIGHT) {
12→  if (!sceneDescriptor) {
13→    return {
14→      floorId: activeFloorId || null,
15→      spawn: null,
16→    };
17→  }
18→
19→  const floor = sceneDescriptor.floors.find((entry) => entry.floorId === activeFloorId)
20→    || sceneDescriptor.floors.find((entry) => entry.floorId === sceneDescriptor.activeFloorId)
21→    || null;
22→
23→  const floorId = floor?.floorId || activeFloorId || sceneDescriptor.activeFloorId || null;
24→  const navigationTarget = floor?.navigationTarget || {
25→    x: sceneDescriptor.defaultTarget.x,
26→    z: sceneDescriptor.defaultTarget.z,
27→  };
28→  const elevation = Number.isFinite(floor?.elevation)
29→    ? floor.elevation
30→    : (sceneDescriptor.groundLevel ?? 0);
31→  const position = {
32→    x: navigationTarget.x,
33→    y: elevation + eyeHeightOffset,
34→    z: navigationTarget.z,
35→  };
36→
37→  return {
38→    floorId,
39→    spawn: {
40→      position,
41→      lookAt: createLookAt(position),
42→      elevation,
43→      eyeHeightOffset,
44→    },
45→  };
46→}
