 1→const MAX_DIMENSION = 100000;
 2→const MIN_DIMENSION = 1;
 3→
 4→export function clampDimension(value, min = MIN_DIMENSION, max = MAX_DIMENSION) {
 5→  if (!Number.isFinite(value)) return min;
 6→  return Math.max(min, Math.min(max, value));
 7→}
 8→
 9→function isValidNumber(v) {
10→  return Number.isFinite(v) && v > 0 && v <= MAX_DIMENSION;
11→}
12→
13→function isFiniteNumber(v) {
14→  return Number.isFinite(v);
15→}
16→
17→const DIMENSION_PROPS = {
18→  panel: ['width', 'depth', 'thickness'],
19→  leg: ['width', 'depth', 'height'],
20→  frame: ['width', 'height', 'length'],
21→  cutout: ['width', 'height', 'depth'],
22→  hole: ['diameter', 'depth'],
23→};
24→
25→export function validatePartDimensions(part) {
26→  const errors = [];
27→  const props = DIMENSION_PROPS[part.type];
28→  if (!props) return { valid: true, errors };
29→
30→  for (const prop of props) {
31→    const val = part[prop];
32→    if (val === undefined || val === null) continue;
33→    if (!isValidNumber(val)) {
34→      errors.push(`${prop}: must be a positive number <= ${MAX_DIMENSION} (got ${val})`);
35→    }
36→  }
37→
38→  return { valid: errors.length === 0, errors };
39→}
40→
41→export function validatePartPosition(part) {
42→  const errors = [];
43→  const pos = part.position;
44→  if (!pos) return { valid: true, errors };
45→
46→  for (const axis of ['x', 'y', 'z']) {
47→    if (!isFiniteNumber(pos[axis])) {
48→      errors.push(`position.${axis}: must be a finite number (got ${pos[axis]})`);
49→    }
50→  }
51→
52→  return { valid: errors.length === 0, errors };
53→}
54→
55→export function validateCutoutFit(cutout, parent) {
56→  const errors = [];
57→  if (!cutout || !parent) return { valid: true, errors };
58→
59→  if (cutout.width > parent.width) {
60→    errors.push(`cutout width (${cutout.width}) exceeds parent width (${parent.width})`);
61→  }
62→  if (cutout.depth && parent.depth && cutout.depth > parent.depth) {
63→    errors.push(`cutout depth (${cutout.depth}) exceeds parent depth (${parent.depth})`);
64→  }
65→
66→  return { valid: errors.length === 0, errors };
67→}
68→
69→export function sanitizePartDimensions(part) {
70→  const props = DIMENSION_PROPS[part.type];
71→  if (!props) return part;
72→
73→  const sanitized = { ...part };
74→  for (const prop of props) {
75→    if (sanitized[prop] !== undefined && sanitized[prop] !== null) {
76→      sanitized[prop] = clampDimension(sanitized[prop]);
77→    }
78→  }
79→  return sanitized;
80→}
81→
82→export function sanitizePartPosition(part) {
83→  if (!part.position) return part;
84→  const pos = { ...part.position };
85→  for (const axis of ['x', 'y', 'z']) {
86→    if (!isFiniteNumber(pos[axis])) pos[axis] = 0;
87→  }
88→  return { ...part, position: pos };
89→}
