58→export function applyDimensionValueToPart(dimension, newMeasurement, part) {
59→  if (!dimension.boundProperty) return null;
60→  return {
61→    partId: part.id,
62→    changes: { [dimension.boundProperty]: newMeasurement },
63→  };
64→}
