 264→function buildRoleMap(parts, objectId) {
 265→  const map = new Map();
 266→  for (const part of parts) {
 267→    if (part.objectId === objectId && part.generatedRole) {
 268→      map.set(part.id, part.generatedRole);
 269→    }
 270→  }
 271→  return map;
 272→}
 273→
 274→function buildReverseRoleMap(parts, objectId) {
 275→  const map = new Map();
 276→  for (const part of parts) {
 277→    if (part.objectId === objectId && part.generatedRole) {
 278→      map.set(part.generatedRole, part.id);
 279→    }
 280→  }
 281→  return map;
 282→}
