 59→export default function SketchCanvas() {
 60→  const svgRef = useRef(null);
 61→  const isPanning = useRef(false);
 62→  const lastPanPos = useRef({ x: 0, y: 0 });
 63→  const spaceHeld = useRef(false);
 64→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 65→
 66→  const { project } = useSketch();
 67→  const {
 68→    activeTool, selectedId, selectedType, toolState,
 69→    viewport, showGrid, activeView, activeAssemblyId, statusMessage, emptyStateDismissed,
 70→    maximizedPanel,
 71→    dispatch: editorDispatch,
 72→  } = useSketchEditor();
 73→
 74→  const tool = useSketchTool();
 75→
 76→  const getModelPos = useCallback((e) => {
 77→    const rect = svgRef.current.getBoundingClientRect();
 78→    return screenToModel(e.clientX, e.clientY, viewport, rect);
 79→  }, [viewport]);
 80→
 81→  const handleMouseDown = useCallback((e) => {
 82→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
 83→      isPanning.current = true;
 84→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 85→      e.preventDefault();
 86→      return;
 87→    }
 88→
 89→    const modelPos = getModelPos(e);
 90→    tool.onMouseDown(modelPos, e, toolState);
 91→  }, [getModelPos, tool, toolState]);
 92→
 93→  const handleMouseMove = useCallback((e) => {
 94→    if (isPanning.current) {
 95→      const dx = e.clientX - lastPanPos.current.x;
 96→      const dy = e.clientY - lastPanPos.current.y;
 97→      editorDispatch({ type: 'PAN', dx, dy });
 98→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 99→      return;
100→    }
101→
102→    const modelPos = getModelPos(e);
103→    setCursorPos(modelPos);
104→    tool.onMouseMove(modelPos, e, toolState, selectedId);
105→  }, [getModelPos, tool, toolState, selectedId, editorDispatch]);
106→
107→  const handleMouseUp = useCallback((e) => {
108→    if (isPanning.current) {
109→      isPanning.current = false;
110→      return;
111→    }
112→
113→    const modelPos = getModelPos(e);
114→    tool.onMouseUp(modelPos, e, toolState);
115→  }, [getModelPos, tool, toolState]);
116→
117→  const handleDoubleClick = useCallback((e) => {
118→    tool.onDoubleClick?.(getModelPos(e), e, toolState);
119→  }, [getModelPos, tool, toolState]);
120→
121→  const handleWheel = useCallback((e) => {
122→    e.preventDefault();
123→    const rect = svgRef.current.getBoundingClientRect();
124→    const mouseX = e.clientX - rect.left;
125→    const mouseY = e.clientY - rect.top;
126→
127→    const direction = e.deltaY < 0 ? 1 : -1;
128→    const factor = direction > 0 ? SKETCH_ZOOM_FACTOR : 1 / SKETCH_ZOOM_FACTOR;
129→    const newZoom = Math.max(SKETCH_MIN_ZOOM, Math.min(SKETCH_MAX_ZOOM, viewport.zoom * factor));
130→
131→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
132→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
133→
134→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
135→  }, [viewport, editorDispatch]);
136→
137→  const handleResetCenterPoint = useCallback(() => {
138→    const rect = svgRef.current?.getBoundingClientRect();
139→    if (!rect) return;
140→
141→    editorDispatch({
142→      type: 'SET_VIEWPORT',
143→      viewport: {
144→        ...viewport,
145→        panX: rect.width / 2,
146→        panY: rect.height / 2,
147→      },
148→    });
149→  }, [editorDispatch, viewport]);
150→
151→  // Keyboard shortcuts
152→  useEffect(() => {
153→    const handleKeyDown = (e) => {
154→      if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.isContentEditable) return;
155→
156→      if (e.key === ' ') {
157→        spaceHeld.current = true;
158→        e.preventDefault();
159→        return;
160→      }
161→
162→      if (e.key === 'Escape') {
163→        if (activeAssemblyId) {
164→          // Let select handler exit edit mode first
165→          tool.onKeyDown(e, toolState, selectedId);
166→          return;
167→        }
168→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
169→        return;
170→      }
171→
172→      if (!e.ctrlKey && !e.metaKey) {
173→        const toolKey = SKETCH_TOOL_SHORTCUTS[e.key.toLowerCase()];
174→        if (toolKey) {
175→          editorDispatch({ type: 'SET_TOOL', tool: toolKey });
176→          return;
177→        }
178→      }
179→
180→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
181→        tool.onKeyDown(e, toolState, selectedId);
182→        return;
183→      }
184→
185→      tool.onKeyDown(e, toolState, selectedId);
186→    };
187→
188→    const handleKeyUp = (e) => {
189→      if (e.key === ' ') {
190→        spaceHeld.current = false;
191→      }
192→    };
193→
194→    window.addEventListener('keydown', handleKeyDown);
195→    window.addEventListener('keyup', handleKeyUp);
196→    return () => {
197→      window.removeEventListener('keydown', handleKeyDown);
198→      window.removeEventListener('keyup', handleKeyUp);
199→    };
200→  }, [editorDispatch, selectedId, activeAssemblyId, tool, toolState]);
201→
202→  // Prevent context menu & attach wheel listener
203→  useEffect(() => {
204→    const svg = svgRef.current;
205→    if (!svg) return;
206→    const prevent = (e) => e.preventDefault();
207→    svg.addEventListener('contextmenu', prevent);
208→    svg.addEventListener('wheel', handleWheel, { passive: false });
209→    return () => {
210→      svg.removeEventListener('contextmenu', prevent);
211→      svg.removeEventListener('wheel', handleWheel);
212→    };
213→  }, [handleWheel]);
214→
215→  // Status message auto-clear
216→  useEffect(() => {
217→    if (!statusMessage) return undefined;
218→    const timer = window.setTimeout(() => {
219→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
220→    }, 2500);
221→    return () => window.clearTimeout(timer);
222→  }, [statusMessage, editorDispatch]);
223→
224→  const cursor = spaceHeld.current ? 'grab' : tool.getCursor(toolState);
225→  const zoomPercent = Math.round(viewport.zoom * 1000);
226→
227→  // Check if project is empty for the empty-state overlay
228→  const hasParts = project.parts.length > 0;
229→  const hasAssemblies = project.assemblies.length > 0;
230→  const showEmptyState = !hasParts && !hasAssemblies && !emptyStateDismissed;
231→
232→  // Split parts from dimensions
233→  const renderParts = project.parts.filter((p) => p.type !== 'dimension');
234→  const dimensions = project.parts.filter((p) => p.type === 'dimension');
235→
236→  // Drag preview for part placement
237→  const drawPreview = toolState.drawing && toolState.startPos && toolState.currentPos
238→    ? {
239→        x: Math.min(toolState.startPos.x, toolState.currentPos.x),
240→        y: Math.min(toolState.startPos.y, toolState.currentPos.y),
241→        width: Math.abs(toolState.currentPos.x - toolState.startPos.x),
242→        height: Math.abs(toolState.currentPos.y - toolState.startPos.y),
243→      }
244→    : null;
245→
246→  // Dimension first-click indicator
247→  const dimFirstClick = activeTool === 'dimension' && toolState.firstPoint;
248→
249→  // Compute XYZ from cursor position using inverse projection
250→  const modelXYZ = viewToModelPosition(cursorPos.x, cursorPos.y, activeView);
251→
252→  return (
253→    <div className={styles.canvasContainer}>
254→      <CompassOverlay className={styles.compassDock} />
255→
256→      <svg
257→        ref={svgRef}
258→        className={styles.svg}
259→        style={{ cursor }}
260→        onPointerDown={handleMouseDown}
261→        onPointerMove={handleMouseMove}
262→        onPointerUp={handleMouseUp}
263→        onDoubleClick={handleDoubleClick}
264→      >
265→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
266→          {showGrid && <GridRenderer />}
267→
268→          {/* Canvas boundary indicator */}
269→          <rect
270→            x={0}
271→            y={0}
272→            width={project.canvasWidth}
273→            height={project.canvasHeight}
274→            fill="none"
275→            stroke="var(--color-border)"
276→            strokeWidth={2}
277→            vectorEffect="non-scaling-stroke"
278→            strokeDasharray="8 4"
279→            style={{ pointerEvents: 'none' }}
280→          />
281→
282→          {/* Rendered parts */}
283→          {renderParts.map((part) => (
284→            <PartRenderer
285→              key={part.id}
286→              part={part}
287→              view={activeView}
288→              isSelected={
289→                part.id === selectedId
290→                || (selectedType === 'object' && part.objectId === selectedId)
291→                || (selectedType === 'assembly' && part.assemblyId === selectedId)
292→              }
293→              zoom={viewport.zoom}
294→              dimmed={!!activeAssemblyId && part.assemblyId !== activeAssemblyId}
295→            />
296→          ))}
297→
298→          {/* Assembly bounding boxes */}
299→          {project.assemblies.map((asm) => (
300→            <AssemblyBoundingBoxRenderer
301→              key={asm.id}
302→              assembly={asm}
303→              parts={project.parts}
304→              view={activeView}
305→              zoom={viewport.zoom}
306→              isSelected={selectedId === asm.id && selectedType === 'assembly'}
307→              isEditMode={activeAssemblyId === asm.id}
308→            />
309→          ))}
310→
311→          {/* Dimension annotations */}
312→          {dimensions.map((dim) => (
313→            <DimensionRenderer
314→              key={dim.id}
315→              dimension={dim}
316→              view={activeView}
317→              zoom={viewport.zoom}
318→              isSelected={dim.id === selectedId}
319→            />
320→          ))}
321→
322→          {/* Draw preview */}
323→          {drawPreview && (
324→            <rect
325→              x={drawPreview.x}
326→              y={drawPreview.y}
327→              width={drawPreview.width}
328→              height={drawPreview.height}
329→              fill="none"
330→              stroke="var(--color-workspace-sketch, #B8860B)"
331→              strokeWidth={2}
332→              vectorEffect="non-scaling-stroke"
333→              strokeDasharray="6 3"
334→              style={{ pointerEvents: 'none' }}
335→            />
336→          )}
337→
338→          {/* Dimension first-click indicator */}
339→          {dimFirstClick && (
340→            <circle
341→              cx={toolState.firstPoint.x}
342→              cy={toolState.firstPoint.y}
343→              r={5 / viewport.zoom}
344→              fill="var(--color-workspace-sketch, #B8860B)"
345→              style={{ pointerEvents: 'none' }}
346→            />
347→          )}
348→        </g>
349→      </svg>
350→
351→      {/* Empty-state overlay */}
352→      {showEmptyState && <SketchEmptyState />}
353→
354→      {/* Overlay controls */}
355→      <div className={styles.overlayControls}>
356→        <button
357→          type="button"
358→          className={styles.overlayBtn}
359→          onClick={handleResetCenterPoint}
360→          title="Center view"
361→        >
362→          <CenterViewIcon />
363→        </button>
364→        <button
365→          type="button"
366→          className={styles.overlayBtn}
367→          onClick={() => editorDispatch({ type: 'TOGGLE_MAXIMIZE_PANEL', panel: 'canvas' })}
368→          title={maximizedPanel === 'canvas' ? 'Restore split view' : 'Maximize canvas'}
369→        >
370→          {maximizedPanel === 'canvas' ? <CollapseIcon /> : <ExpandIcon />}
371→        </button>
372→      </div>
373→
374→      {/* Status bar */}
375→      <div className={styles.statusBar} role="status" aria-live="polite">
376→        <span className={styles.statusContext}>{getViewLabel(activeView)}</span>
377→        <span className={styles.statusCoords}>X: {Math.round(modelXYZ.x)} mm</span>
378→        <span className={styles.statusCoords}>Y: {Math.round(modelXYZ.y)} mm</span>
379→        <span className={styles.statusCoords}>Z: {Math.round(modelXYZ.z)} mm</span>
380→        <span className={styles.statusContext}>Zoom: {zoomPercent}%</span>
381→        {activeAssemblyId && (
382→          <span className={styles.statusContext} style={{ color: '#4682B4', fontWeight: 600 }}>
383→            Focus: {project.assemblies.find((a) => a.id === activeAssemblyId)?.name || 'Assembly'}
384→          </span>
385→        )}
386→        <span className={styles.statusTool}>{activeTool}</span>
387→      </div>
388→
389→      {/* Toast notifications */}
390→      {statusMessage && (
391→        <div className={styles.toast}>
392→          {statusMessage}
393→          <div className={styles.toastProgress} />
394→        </div>
395→      )}
396→    </div>
397→  );
398→}
