 3→export default function PartRenderer({ part, view, isSelected = false, zoom = 1, dimmed = false }) {
 4→  const { svgX, svgY, svgWidth, svgHeight } = projectPartToView(part, view);
 5→
 6→  const isSubtractive = part.type === 'cutout' || part.type === 'hole';
 7→  const fill = isSubtractive ? 'rgba(200, 200, 200, 0.3)' : (part.fill || 'none');
 8→  const stroke = part.stroke || '#1E2433';
 9→  const strokeDash = isSubtractive ? `${6 / zoom} ${4 / zoom}` : undefined;
10→
11→  const isHoleInTop = part.type === 'hole' && view === 'top';
12→
13→  return (
14→    <g data-part-id={part.id} opacity={dimmed ? 0.3 : 1}>
15→      {isHoleInTop ? (
16→        <ellipse
17→          cx={svgX + svgWidth / 2}
18→          cy={svgY + svgHeight / 2}
19→          rx={svgWidth / 2}
20→          ry={svgHeight / 2}
21→          fill={fill}
22→          stroke={stroke}
23→          strokeWidth={part.strokeWidth || 2}
24→          vectorEffect="non-scaling-stroke"
25→          strokeDasharray={strokeDash}
26→        />
27→      ) : (
28→        <rect
29→          x={svgX}
30→          y={svgY}
31→          width={svgWidth}
32→          height={svgHeight}
33→          fill={fill}
34→          stroke={stroke}
35→          strokeWidth={part.strokeWidth || 2}
36→          vectorEffect="non-scaling-stroke"
37→          strokeDasharray={strokeDash}
38→        />
39→      )}
40→      {isSelected && (
41→        <rect
42→          x={svgX - 4 / zoom}
43→          y={svgY - 4 / zoom}
44→          width={svgWidth + 8 / zoom}
45→          height={svgHeight + 8 / zoom}
46→          fill="none"
47→          stroke="var(--color-workspace-sketch, #B8860B)"
48→          strokeWidth={1.5 / zoom}
49→          strokeDasharray={`${4 / zoom} ${3 / zoom}`}
50→          style={{ pointerEvents: 'none' }}
51→        />
52→      )}
53→    </g>
54→  );
55→}
