 6→export function createDimensionHandler({ dispatch, editorDispatch, activeView, snapEnabled }) {
 7→  return {
 8→    onMouseDown(modelPos, e, toolState) {
 9→      if (e.button !== 0) return;
10→
11→      const pos = snapEnabled ? snapPoint(modelPos, SKETCH_GRID_MINOR) : modelPos;
12→
13→      if (!toolState.firstPoint) {
14→        // First click - set start point
15→        editorDispatch({
16→          type: 'UPDATE_TOOL_STATE',
17→          payload: {
18→            firstPoint: { x: pos.x, y: pos.y },
19→          },
20→        });
21→        editorDispatch({
22→          type: 'SET_STATUS_MESSAGE',
23→          message: 'Click second point for dimension.',
24→        });
25→      } else {
26→        // Second click - create dimension
27→        const start3D = viewToModelPosition(toolState.firstPoint.x, toolState.firstPoint.y, activeView);
28→        const end3D = viewToModelPosition(pos.x, pos.y, activeView);
29→
30→        const dim = createDimension({
31→          startPoint: start3D,
32→          endPoint: end3D,
33→          offset: 200,
34→        });
35→
36→        dispatch({ type: 'PART_ADD', part: dim });
37→
38→        editorDispatch({
39→          type: 'UPDATE_TOOL_STATE',
40→          payload: { firstPoint: null },
41→        });
42→
43→        editorDispatch({
44→          type: 'SET_STATUS_MESSAGE',
45→          message: 'Dimension placed.',
46→        });
47→      }
48→    },
49→
50→    onMouseMove() {},
51→
52→    onMouseUp() {},
53→
54→    onKeyDown(e) {
55→      if (e.key === 'Escape') {
56→        editorDispatch({
57→          type: 'UPDATE_TOOL_STATE',
58→          payload: { firstPoint: null },
59→        });
60→      }
61→    },
62→
63→    getCursor() {
64→      return 'crosshair';
65→    },
66→  };
67→}
