  3→export function projectDimensionPoint(point, view) {
  4→  switch (view) {
  5→    case 'top':
  6→      return { x: point.x, y: point.y };
  7→    case 'front':
  8→      return { x: point.x, y: -(point.z || 0) };
  9→    case 'side':
 10→      return { x: point.y, y: -(point.z || 0) };
 11→    default:
 12→      return { x: point.x, y: point.y };
 13→  }
 14→}
 15→
 16→export default function DimensionRenderer({ dimension, view, zoom = 1, isSelected = false }) {
 17→  const start2D = projectDimensionPoint(dimension.startPoint, view);
 18→  const end2D = projectDimensionPoint(dimension.endPoint, view);
 19→
 20→  const figure = createDimensionFigure({
 21→    id: dimension.id,
 22→    startPoint: start2D,
 23→    endPoint: end2D,
 24→    mode: 'aligned',
 25→    offset: dimension.offset || 200,
 26→    label: dimension.textOverride || undefined,
 27→    source: 'manual',
 28→  });
 29→
 30→  if (!figure) return null;
 31→
 32→  const hitPad = 8 / zoom;
 33→
 34→  return (
 35→    <g data-part-id={dimension.id}>
 36→      {/* Invisible wide hit area along dimension line */}
 37→      <line
 38→        x1={figure.lineStart.x}
 39→        y1={figure.lineStart.y}
 40→        x2={figure.lineEnd.x}
 41→        y2={figure.lineEnd.y}
 42→        stroke="transparent"
 43→        strokeWidth={hitPad * 2}
 44→        style={{ cursor: 'pointer' }}
 45→      />
 46→
 47→      {/* Extension lines */}
 48→      {figure.extensionLines.map((line, i) => (
 49→        <line
 50→          key={`ext-${i}`}
 51→          x1={line.start.x}
 52→          y1={line.start.y}
 53→          x2={line.end.x}
 54→          y2={line.end.y}
 55→          stroke="#666"
 56→          strokeWidth={1}
 57→          vectorEffect="non-scaling-stroke"
 58→        />
 59→      ))}
 60→
 61→      {/* Dimension line */}
 62→      <line
 63→        x1={figure.lineStart.x}
 64→        y1={figure.lineStart.y}
 65→        x2={figure.lineEnd.x}
 66→        y2={figure.lineEnd.y}
 67→        stroke={isSelected ? '#B8860B' : '#1E2433'}
 68→        strokeWidth={isSelected ? 2 : 1}
 69→        vectorEffect="non-scaling-stroke"
 70→      />
 71→
 72→      {/* Arrowheads */}
 73→      {figure.arrowheads.map((arrow, i) => (
 74→        <polygon
 75→          key={`arrow-${i}`}
 76→          points={`${arrow.tip.x},${arrow.tip.y} ${arrow.left.x},${arrow.left.y} ${arrow.right.x},${arrow.right.y}`}
 77→          fill={isSelected ? '#B8860B' : '#1E2433'}
 78→        />
 79→      ))}
 80→
 81→      {/* Text label */}
 82→      <text
 83→        x={figure.text.position.x}
 84→        y={figure.text.position.y}
 85→        textAnchor="middle"
 86→        dominantBaseline="central"
 87→        transform={`rotate(${figure.text.angle} ${figure.text.position.x} ${figure.text.position.y})`}
 88→        fontSize={120}
 89→        fontFamily="var(--font-blueprint, monospace)"
 90→        fill={isSelected ? '#B8860B' : '#1E2433'}
 91→      >
 92→        {figure.text.value}
 93→      </text>
 94→
 95→      {/* Selection highlight */}
 96→      {isSelected && (
 97→        <rect
 98→          x={Math.min(figure.lineStart.x, figure.lineEnd.x) - hitPad}
 99→          y={Math.min(figure.lineStart.y, figure.lineEnd.y) - hitPad - Math.abs(dimension.offset || 200)}
100→          width={Math.abs(figure.lineEnd.x - figure.lineStart.x) + hitPad * 2}
101→          height={Math.abs(figure.lineEnd.y - figure.lineStart.y) + hitPad * 2 + Math.abs(dimension.offset || 200)}
102→          fill="none"
103→          stroke="#B8860B"
104→          strokeWidth={1}
105→          strokeDasharray="4 3"
106→          vectorEffect="non-scaling-stroke"
107→          style={{ pointerEvents: 'none' }}
108→        />
109→      )}
110→    </g>
111→  );
112→}
