 13→export default function SketchPreviewPanel({ isMaximized = false, onToggleMaximize, className = '' }) {
 14→  const containerRef = useRef(null);
 15→  const viewportRef = useRef(null);
 16→  const rootRef = useRef(null);
 17→  const resizeObserverRef = useRef(null);
 18→  const compassNeedleRef = useRef(null);
 19→
 20→  const { project } = useSketch();
 21→  const { selectedId, selectedType, dispatch: editorDispatch } = useSketchEditor();
 22→  const [previewScope, setPreviewScope] = useState('all');
 23→
 24→  const previewOptions = useMemo(() => {
 25→    const options = [{ value: 'all', label: 'All Objects' }];
 26→    for (const object of project.objects || []) {
 27→      options.push({ value: `object:${object.id}`, label: object.name });
 28→    }
 29→    if (project.parts.some((part) => !part.objectId && part.type !== 'dimension' && part.type !== 'cutout' && part.type !== 'hole')) {
 30→      options.push({ value: 'manual', label: 'Custom Assemblies' });
 31→    }
 32→    return options;
 33→  }, [project.objects, project.parts]);
 34→
 35→  const visibleParts = useMemo(() => {
 36→    const renderable = project.parts.filter(
 37→      (part) => part.type !== 'dimension' && part.type !== 'cutout' && part.type !== 'hole'
 38→    );
 39→    if (previewScope === 'all') return renderable;
 40→    if (previewScope === 'manual') return renderable.filter((part) => !part.objectId);
 41→    if (previewScope.startsWith('object:')) {
 42→      const objectId = previewScope.slice('object:'.length);
 43→      return renderable.filter((part) => part.objectId === objectId);
 44→    }
 45→    return renderable;
 46→  }, [project.parts, previewScope]);
 47→
 48→  const inspection = useMemo(
 49→    () => getSketchInspection(project, selectedId, selectedType),
 50→    [project, selectedId, selectedType]
 51→  );
 52→
 53→  useEffect(() => {
 54→    if (selectedType === 'object' && selectedId) {
 55→      setPreviewScope(`object:${selectedId}`);
 56→    }
 57→  }, [selectedId, selectedType]);
 58→
 59→  const handlePreviewPick = useCallback((target) => {
 60→    if (!target?.sourceId || !target?.kind) {
 61→      editorDispatch({ type: 'DESELECT' });
 62→      return;
 63→    }
 64→    editorDispatch({ type: 'SELECT_OBJECT', id: target.sourceId, objectType: target.kind });
 65→  }, [editorDispatch]);
 66→
 67→  useEffect(() => {
 68→    const container = containerRef.current;
 69→    if (!container) return undefined;
 70→
 71→    const viewport = createPreviewViewport(container);
 72→    viewport.setNavigationMode('inspect');
 73→    viewportRef.current = viewport;
 74→
 75→    if ('ResizeObserver' in window) {
 76→      const observer = new ResizeObserver(() => viewport.resize());
 77→      observer.observe(container);
 78→      resizeObserverRef.current = observer;
 79→    }
 80→
 81→    viewport.setPickHandler(handlePreviewPick);
 82→    viewport.setCompassHeadingHandler((headingDeg) => {
 83→      if (!compassNeedleRef.current) return;
 84→      compassNeedleRef.current.style.setProperty('--compass-heading', `${headingDeg}deg`);
 85→    });
 86→    viewport.resize();
 87→
 88→    return () => {
 89→      resizeObserverRef.current?.disconnect?.();
 90→      resizeObserverRef.current = null;
 91→      if (rootRef.current) {
 92→        disposeScene(rootRef.current, { disposeMaterials: true });
 93→        rootRef.current = null;
 94→      }
 95→      viewport.dispose();
 96→      viewportRef.current = null;
 97→    };
 98→  }, [handlePreviewPick]);
 99→
100→  useEffect(() => {
101→    const viewport = viewportRef.current;
102→    if (!viewport) return;
103→
104→    if (rootRef.current) {
105→      disposeScene(rootRef.current, { disposeMaterials: true });
106→    }
107→
108→    const root = buildSketchPreviewRoot(visibleParts, { selectedId, selectedType });
109→    rootRef.current = root;
110→
111→    const box = new THREE.Box3();
112→    root.updateMatrixWorld(true);
113→    box.expandByObject(root);
114→
115→    if (box.isEmpty()) {
116→      box.set(
117→        new THREE.Vector3(-500, 0, -300),
118→        new THREE.Vector3(500, 800, 300)
119→      );
120→    }
121→
122→    viewport.setWorld(root, {
123→      min: { x: box.min.x, y: box.min.y, z: box.min.z },
124→      max: { x: box.max.x, y: box.max.y, z: box.max.z },
125→    }, 0);
126→  }, [visibleParts, selectedId, selectedType]);
127→
128→  return (
129→    <section className={`${styles.panel} ${className}`}>
130→      <div className={styles.header}>
131→        <div className={styles.titleGroup}>
132→          <span className={styles.eyebrow}>3D Preview</span>
133→          <span className={styles.title}>
134→            {visibleParts.length === 1 ? '1 part' : `${visibleParts.length} parts`}
135→          </span>
136→        </div>
137→        <div className={styles.actions}>
138→          <select
139→            className={styles.assemblySelect}
140→            value={previewOptions.some((option) => option.value === previewScope) ? previewScope : 'all'}
141→            onChange={(event) => {
142→              const value = event.target.value;
143→              setPreviewScope(value);
144→              if (value.startsWith('object:')) {
145→                editorDispatch({ type: 'SELECT_OBJECT', id: value.slice('object:'.length), objectType: 'object' });
146→                return;
147→              }
148→              editorDispatch({ type: 'DESELECT' });
149→            }}
150→          >

  1→import * as THREE from 'three';
  2→
  3→const WOOD_COLOR = 0xD2B48C;
  4→const SELECTED_TINT = 0xB8860B;
  5→const EDGE_COLOR = 0x333333;
  6→
  7→function createBoxMesh(width, height, depth, color) {
  8→  const geometry = new THREE.BoxGeometry(width, height, depth);
  9→  const material = new THREE.MeshStandardMaterial({
 10→    color,
 11→    roughness: 0.7,
 12→    metalness: 0.05,
 13→  });
 14→  return new THREE.Mesh(geometry, material);
 15→}
 16→
 17→function createCylinderMesh(diameter, height, color) {
 18→  const geometry = new THREE.CylinderGeometry(diameter / 2, diameter / 2, height, 16);
 19→  const material = new THREE.MeshStandardMaterial({
 20→    color,
 21→    roughness: 0.7,
 22→    metalness: 0.05,
 23→  });
 24→  return new THREE.Mesh(geometry, material);
 25→}
 26→
 27→function addEdges(mesh) {
 28→  const edges = new THREE.EdgesGeometry(mesh.geometry);
 29→  const line = new THREE.LineSegments(
 30→    edges,
 31→    new THREE.LineBasicMaterial({ color: EDGE_COLOR, transparent: true, opacity: 0.3 })
 32→  );
 33→  mesh.add(line);
 34→}
 35→
 36→function createPanelMesh(part, isSelected) {
 37→  const color = isSelected ? SELECTED_TINT : WOOD_COLOR;
 38→  const mesh = createBoxMesh(part.width, part.thickness, part.depth, color);
 39→  // Three.js: x = part.x + w/2, y = part.z + h/2, z = part.y + d/2
 40→  mesh.position.set(
 41→    part.position.x + part.width / 2,
 42→    part.position.z + part.thickness / 2,
 43→    part.position.y + part.depth / 2
 44→  );
 45→  addEdges(mesh);
 46→  return mesh;
 47→}
 48→
 49→function createLegMesh(part, isSelected) {
 50→  const color = isSelected ? SELECTED_TINT : 0x8B7355;
 51→
 52→  if (part.profile === 'round') {
 53→    const mesh = createCylinderMesh(part.width, part.height, color);
 54→    mesh.position.set(
 55→      part.position.x + part.width / 2,
 56→      part.position.z + part.height / 2,
 57→      part.position.y + part.depth / 2
 58→    );
 59→    addEdges(mesh);
 60→    return mesh;
 61→  }
 62→
 63→  const mesh = createBoxMesh(part.width, part.height, part.depth, color);
 64→  mesh.position.set(
 65→    part.position.x + part.width / 2,
 66→    part.position.z + part.height / 2,
 67→    part.position.y + part.depth / 2
 68→  );
 69→  addEdges(mesh);
 70→  return mesh;
 71→}
 72→
 73→function createFrameMesh(part, isSelected) {
 74→  const color = isSelected ? SELECTED_TINT : 0xA0522D;
 75→  let w, h, d;
 76→
 77→  if (part.axis === 'y') {
 78→    w = part.width;
 79→    h = part.height;
 80→    d = part.length;
 81→  } else {
 82→    w = part.length;
 83→    h = part.height;
 84→    d = part.width;
 85→  }
 86→
 87→  const mesh = createBoxMesh(w, h, d, color);
 88→  mesh.position.set(
 89→    part.position.x + w / 2,
 90→    part.position.z + h / 2,
 91→    part.position.y + d / 2
 92→  );
 93→  addEdges(mesh);
 94→  return mesh;
 95→}
 96→
 97→function isPartSelected(part, selection) {
 98→  if (!selection) return false;
 99→  if (selection.selectedType === 'object') return part.objectId === selection.selectedId;
100→  return part.id === selection.selectedId;
101→}
102→
103→export function buildSketchPreviewRoot(parts, selection) {
104→  const root = new THREE.Group();
105→
106→  for (const part of parts) {
107→    // Skip dimension, cutout, hole in 3D for V1
108→    if (part.type === 'dimension' || part.type === 'cutout' || part.type === 'hole') continue;
109→
110→    const isSelected = isPartSelected(part, selection);
111→    let mesh;
112→
113→    switch (part.type) {
114→      case 'panel':
115→        mesh = createPanelMesh(part, isSelected);
116→        break;
117→      case 'leg':
118→        mesh = createLegMesh(part, isSelected);
119→        break;
120→      case 'frame':
121→        mesh = createFrameMesh(part, isSelected);
122→        break;
123→      default:
124→        continue;
125→    }
126→
127→    if (mesh) {
128→      const previewTarget = part.objectId
129→        ? { sourceId: part.objectId, kind: 'object' }
130→        : { sourceId: part.id, kind: 'part' };
131→      mesh.userData.previewTarget = previewTarget;
132→      root.add(mesh);
133→    }
134→  }
135→
136→  return root;
137→}
