 1→import {
 2→  buildAssemblyDraftSource,
 3→  buildObjectDraftSource,
 4→  buildPartDetailSource,
 5→  buildPartListSource,
 6→} from '../domain/objectDrafting';
 7→
 8→function extractView(sourceView) {
 9→  if (sourceView === 'sketch_object_top' || sourceView === 'sketch_assembly_top') return 'top';
10→  if (sourceView === 'sketch_object_front' || sourceView === 'sketch_assembly_front') return 'front';
11→  if (sourceView === 'sketch_object_side' || sourceView === 'sketch_assembly_side') return 'side';
12→  return 'top';
13→}
14→
15→export function resolveSketchViewportSource(sketchProject, viewport) {
16→  const { sourceView, sourceRefId } = viewport;
17→
18→  if (sourceView === 'sketch_object_top' || sourceView === 'sketch_object_front' || sourceView === 'sketch_object_side') {
19→    return buildObjectDraftSource(sketchProject, sourceRefId, extractView(sourceView));
20→  }
21→
22→  if (sourceView === 'sketch_assembly_top' || sourceView === 'sketch_assembly_front' || sourceView === 'sketch_assembly_side') {
23→    return buildAssemblyDraftSource(sketchProject, sourceRefId, extractView(sourceView));
24→  }
25→
26→  if (sourceView === 'sketch_part_detail') {
27→    return buildPartDetailSource(sketchProject, sourceRefId);
28→  }
29→
30→  if (sourceView === 'sketch_part_list') {
31→    const sourceObjectId = viewport.sourceObjectId || null;
32→    if (sourceObjectId) {
33→      return buildPartListSource(sketchProject, { objectId: sourceObjectId });
34→    }
35→    if (sourceRefId) {
36→      const objectExists = (sketchProject.objects || []).some((object) => object.id === sourceRefId);
37→      if (objectExists) return buildPartListSource(sketchProject, { objectId: sourceRefId });
38→      return buildPartListSource(sketchProject, { assemblyId: sourceRefId });
39→    }
40→    return buildPartListSource(sketchProject, {});
41→  }
42→
43→  return {
44→    kind: 'empty',
45→    title: 'Unknown Source',
46→    message: `Unknown source view: ${sourceView}`,
47→    bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
48→  };
49→}
50→
51→export function getSketchViewportSourceLabel(sourceView) {
52→  switch (sourceView) {
53→    case 'sketch_object_top': return 'Object Top';
54→    case 'sketch_object_front': return 'Object Front';
55→    case 'sketch_object_side': return 'Object Side';
56→    case 'sketch_assembly_top': return 'Assembly Top';
57→    case 'sketch_assembly_front': return 'Assembly Front';
58→    case 'sketch_assembly_side': return 'Assembly Side';
59→    case 'sketch_part_detail': return 'Part Detail';
60→    case 'sketch_part_list': return 'Parts List';
61→    default: return 'Unknown';
62→  }
63→}
