.layout {
  display: grid;
  grid-template-rows: var(--toolbar-height, 52px) 1fr;
  grid-template-columns: var(--sidebar-width, 240px) 1fr 280px;
  grid-template-areas:
    "toolbar toolbar toolbar"
    "sidebar canvas rightpanel";
  height: 100%;
  width: 100%;
}

.toolbar {
  grid-area: toolbar;
  position: relative;
  z-index: 10;
}

.sidebar {
  grid-area: sidebar;
  min-height: 0;
  overflow-y: auto;
}

.canvas {
  grid-area: canvas;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
  box-shadow: inset 1px 0 3px rgba(0, 0, 0, 0.04), inset -1px 0 3px rgba(0, 0, 0, 0.04);
}

.rightPanel {
  grid-area: rightpanel;
  display: flex;
  flex-direction: column;
  min-height: 0;
  overflow-y: auto;
}

.modelWorkspace {
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(300px, 28vw);
  width: 100%;
  height: 100%;
  min-width: 0;
  min-height: 0;
}

.primaryCanvas {
  min-width: 0;
  min-height: 0;
}

.preview {
  display: flex;
  min-width: 0;
  min-height: 0;
  height: 100%;
  overflow: hidden;
}

.previewFallback {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  height: 100%;
  min-height: 0;
  font-size: 13px;
  color: var(--color-text-secondary);
  background: radial-gradient(circle at top, rgba(255, 255, 255, 0.6), rgba(243, 243, 240, 0.9)),
    linear-gradient(180deg, #F3F3F0, #EAEAE7);
  border-left: 1px solid var(--color-border);
  position: relative;
  overflow: hidden;
}

.previewFallback::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.4), transparent);
  animation: shimmer 1.5s infinite;
}

@keyframes shimmer {
  from { transform: translateX(-100%); }
  to { transform: translateX(100%); }
}

.workspaceMaximized {
  grid-template-columns: 1fr;
}

@media (max-width: 1200px) {
  .modelWorkspace {
    grid-template-columns: minmax(0, 1fr);
    grid-template-rows: minmax(0, 1fr) 280px;
