  const timer = new THREE.Timer();
  timer.connect(document);

  const camera = new THREE.PerspectiveCamera(42, 1, 10, 100000);
  const renderer = new THREE.WebGLRenderer({
    antialias: true,
    alpha: true,
    powerPreference: 'high-performance',
  });
