175→function SketchInner() {
176→  const { project, isDirty, dispatch } = useSketch();
177→  const { maximizedPanel, workspaceMode, activeSheetId, dispatch: editorDispatch } = useSketchEditor();
178→  const [showLoadModal, setShowLoadModal] = useState(false);
179→  const [showTemplateDialog, setShowTemplateDialog] = useState(false);
180→  const [fileHandle, setFileHandle] = useState(null);
181→
182→  // Autosave
183→  useSketchAutosave(project, isDirty, dispatch);
184→
185→  // beforeunload warning
186→  useEffect(() => {
187→    const handler = (e) => {
188→      if (isDirty) {
189→        e.preventDefault();
190→        e.returnValue = '';
191→      }
192→    };
193→    window.addEventListener('beforeunload', handler);
194→    return () => window.removeEventListener('beforeunload', handler);
195→  }, [isDirty]);
196→
197→  // Ctrl+S file save
198→  useEffect(() => {
199→    const handler = async (e) => {
200→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
201→        e.preventDefault();
202→        try {
203→          const result = await exportSketchProjectFile(project, { fileHandle });
204→          if (result.fileHandle) setFileHandle(result.fileHandle);
205→          await saveSketchProject(project);
206→          dispatch({ type: 'MARK_SAVED' });
207→        } catch (err) {
208→          if (!isFilePickerAbortError(err)) {
209→            console.error('Save failed:', err);
210→          }
211→        }
212→      }
213→    };
214→    window.addEventListener('keydown', handler);
215→    return () => window.removeEventListener('keydown', handler);
216→  }, [project, fileHandle, dispatch]);
217→
218→  // If active sheet was deleted, revert to model mode
219→  useEffect(() => {
220→    if (workspaceMode === 'sheet' && activeSheetId) {
221→      const sheetExists = (project.sheets || []).some((s) => s.id === activeSheetId);
222→      if (!sheetExists) {
223→        editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
224→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
225→      }
226→    }
227→  }, [workspaceMode, activeSheetId, project.sheets, editorDispatch]);
228→
229→  const handleNew = useCallback(() => {
230→    if (isDirty && !window.confirm('You have unsaved changes. Start a new project?')) return;
231→    dispatch({ type: 'SKETCH_NEW' });
232→    setFileHandle(null);
233→  }, [isDirty, dispatch]);
234→
235→  const handleSave = useCallback(async () => {
236→    try {
237→      const result = await exportSketchProjectFile(project, { fileHandle });
238→      if (result.fileHandle) setFileHandle(result.fileHandle);
239→      await saveSketchProject(project);
240→      dispatch({ type: 'MARK_SAVED' });
241→    } catch (err) {
242→      if (!isFilePickerAbortError(err)) {
243→        console.error('Save failed:', err);
244→      }
245→    }
246→  }, [project, fileHandle, dispatch]);
247→
248→  const handleLoadClick = useCallback(() => {
249→    setShowLoadModal(true);
250→  }, []);
251→
252→  const isSheetMode = workspaceMode === 'sheet';
253→
254→  return (
255→    <SketchProjectContext.Provider value={{ handleNew, handleSave, handleLoadClick, fileHandle, setFileHandle, showTemplateDialog, setShowTemplateDialog }}>
256→      <div className={styles.layout}>
257→        <div className={styles.toolbar}>
258→          <SketchToolbar />
259→        </div>
260→        <div className={styles.sidebar}>
261→          <SketchSidebar />
262→        </div>
263→        <div className={styles.canvas}>
264→          {isSheetMode ? (
265→            <Suspense fallback={<div className={styles.previewFallback}>Loading sheet...</div>}>
266→              <SketchSheetCanvas />
267→            </Suspense>
268→          ) : (
269→            <div className={`${styles.modelWorkspace} ${maximizedPanel ? styles.workspaceMaximized : ''}`}>
270→              {maximizedPanel !== 'preview' && (
271→                <div className={styles.primaryCanvas}>
272→                  <SketchCanvas />
273→                </div>
274→              )}
275→              {maximizedPanel !== 'canvas' && (
276→                <div className={styles.preview}>
277→                  <Suspense fallback={<div className={styles.previewFallback}>Loading 3D preview...</div>}>
278→                    <SketchPreviewPanel
279→                      isMaximized={maximizedPanel === 'preview'}
280→                      onToggleMaximize={() => editorDispatch({ type: 'TOGGLE_MAXIMIZE_PANEL', panel: 'preview' })}
281→                    />
282→                  </Suspense>
283→                </div>
284→              )}
285→            </div>
286→          )}
287→        </div>
288→        <div className={styles.rightPanel}>
289→          <SketchPropertiesPanel />
290→        </div>
291→      </div>
292→      {showLoadModal && <SketchLoadModal onClose={() => setShowLoadModal(false)} />}
293→      {showTemplateDialog && (
294→        <TemplateDialog
295→          onClose={() => setShowTemplateDialog(false)}
296→          onGenerate={(templateType, params) => {
297→            const objectId = generateId('obj');
298→            dispatch({ type: 'TEMPLATE_GENERATE', templateType, params, objectId });
299→            editorDispatch({ type: 'DISMISS_EMPTY_STATE' });
300→            editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: null });
301→            editorDispatch({ type: 'SELECT_OBJECT', id: objectId, objectType: 'object' });
302→          }}
303→        />
304→      )}
305→    </SketchProjectContext.Provider>
306→  );
307→}
