 410→    }
 411→
 412→    case 'PART_DELETE': {
 413→      const managedObject = getManagedObjectForPart(state.project, action.partId);
 414→      if (managedObject) return state;
 415→
 416→      const partId = action.partId;
 417→      const childIds = new Set(
 418→        state.project.parts.filter((part) => part.parentId === partId).map((part) => part.id)
 419→      );
 420→      const idsToRemove = new Set([partId, ...childIds]);
 421→
 422→      const constraints = filterConstraintsForRemovedParts(
 423→        state.project.constraints || [],
 424→        idsToRemove
 425→      );
 426→
 427→      return applyUpdate(state, {
 428→        ...state.project,
 429→        updatedAt: new Date().toISOString(),
 430→        parts: state.project.parts
 431→          .filter((part) => !idsToRemove.has(part.id))
 432→          .map((part) => {
 433→            if (part.type === 'dimension' && part.boundPartId && idsToRemove.has(part.boundPartId)) {
 434→              return { ...part, boundPartId: null, boundProperty: null, boundAxis: null };
 435→            }
 436→            return part;
 437→          }),
 438→        assemblies: state.project.assemblies.map((assembly) => ({
 439→          ...assembly,
 440→          partIds: assembly.partIds.filter((id) => !idsToRemove.has(id)),
 441→        })),
 442→        constraints,
