 450→      const part = state.project.parts.find((entry) => entry.id === action.partId);
 451→      if (!part) return state;
 452→
 453→      const idMap = new Map();
 454→      const cloned = clonePart(part, idMap);
 455→      const children = state.project.parts.filter((entry) => entry.parentId === action.partId);
 456→      const clonedChildren = children.map((child) => {
 457→        const clonedChild = clonePart(child, idMap);
 458→        clonedChild.parentId = cloned.id;
 459→        return clonedChild;
 460→      });
 461→
 462→      const newParts = [cloned, ...clonedChildren];
 463→      let assemblies = state.project.assemblies;
 464→      if (part.assemblyId) {
 465→        assemblies = assemblies.map((assembly) => {
 466→          if (assembly.id === part.assemblyId) {
 467→            return {
 468→              ...assembly,
 469→              partIds: [...assembly.partIds, ...newParts.map((entry) => entry.id)],
 470→            };
 471→          }
 472→          return assembly;
 473→        });
 474→        for (const nextPart of newParts) {
 475→          nextPart.assemblyId = part.assemblyId;
 476→        }
 477→      }
 478→
 479→      return applyUpdate(state, {
 480→        ...state.project,
 481→        updatedAt: new Date().toISOString(),
 482→        parts: [...state.project.parts, ...newParts],
 483→        assemblies,
 484→      });
 485→    }
 486→
 487→    case 'ASSEMBLY_ADD':
 488→      return applyUpdate(state, {
 489→        ...state.project,
 490→        updatedAt: new Date().toISOString(),
 491→        assemblies: [...state.project.assemblies, { ...action.assembly, source: action.assembly.source || 'manual' }],
 492→      });
 493→
 494→    case 'ASSEMBLY_UPDATE': {
 495→      const managedObject = getManagedObjectForAssembly(state.project, action.assembly.id);
 496→      if (managedObject) return state;
 497→
 498→      return applyUpdate(state, {
 499→        ...state.project,
 500→        updatedAt: new Date().toISOString(),
 501→        assemblies: state.project.assemblies.map((assembly) => (
 502→          assembly.id === action.assembly.id ? { ...assembly, ...action.assembly } : assembly
 503→        )),
 504→      });
 505→    }
 506→
 507→    case 'ASSEMBLY_DELETE': {
 508→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 509→      if (managedObject) return state;
 510→
 511→      const assemblyId = action.assemblyId;
 512→      return applyUpdate(state, {
 513→        ...state.project,
 514→        updatedAt: new Date().toISOString(),
 515→        assemblies: state.project.assemblies.filter((assembly) => assembly.id !== assemblyId),
 516→        parts: state.project.parts.map((part) => (
 517→          part.assemblyId === assemblyId ? { ...part, assemblyId: null } : part
 518→        )),
 519→      });
 520→    }
 521→
 522→    case 'ASSEMBLY_MOVE': {
 523→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 524→      if (managedObject) {
 525→        return sketchReducer(state, {
 526→          type: 'OBJECT_MOVE',
 527→          objectId: managedObject.id,
 528→          delta: action.delta,
 529→        });
 530→      }
 531→
 532→      const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
 533→      if (!assembly) return state;
 534→
 535→      const partIdSet = new Set(assembly.partIds);
 536→      let nextProject = {
 537→        ...state.project,
 538→        updatedAt: new Date().toISOString(),
 539→        parts: state.project.parts.map((part) => {
 540→          if (!partIdSet.has(part.id) || part.type === 'dimension') return part;
 541→          const moved = {
 542→            ...part,
 543→            position: {
 544→              x: part.position.x + (action.delta.dx || 0),
 545→              y: part.position.y + (action.delta.dy || 0),
 546→              z: part.position.z + (action.delta.dz || 0),
 547→            },
 548→          };
 549→          return sanitizePart(moved);
 550→        }),
 551→      };
 552→      nextProject = applyConstraints(nextProject);
 553→      for (const partId of partIdSet) {
 554→        nextProject = updateBoundDimensions(nextProject, partId);
 555→      }
 556→      return applyUpdate(state, nextProject);
 557→    }
 558→
 559→    case 'ASSEMBLY_DELETE_WITH_PARTS': {
 560→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 561→      if (managedObject) {
 562→        return sketchReducer(state, {
 563→          type: 'OBJECT_DELETE',
 564→          objectId: managedObject.id,
 565→        });
 566→      }
 567→
 568→      const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
 569→      if (!assembly) return state;
 570→
 571→      return applyUpdate(state, {
 572→        ...removePartsAndAssemblies(state.project, {
 573→          partIds: assembly.partIds,
 574→          assemblyIds: [assembly.id],
 575→        }),
 576→        updatedAt: new Date().toISOString(),
 577→      });
 578→    }
 579→
 580→    case 'ASSEMBLY_ADD_PART': {
 581→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 582→      if (managedObject) return state;
 583→
 584→       const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
 585→
 586→      return applyUpdate(state, {
 587→        ...state.project,
 588→        updatedAt: new Date().toISOString(),
 589→        assemblies: state.project.assemblies.map((assembly) => (
 590→          assembly.id === action.assemblyId && !assembly.partIds.includes(action.partId)
 591→            ? { ...assembly, partIds: [...assembly.partIds, action.partId] }
 592→            : assembly
 593→        )),
 594→        parts: state.project.parts.map((part) => (
 595→          part.id === action.partId
 596→            ? { ...part, assemblyId: action.assemblyId, objectId: assembly?.objectId || part.objectId || null }
 597→            : part
 598→        )),
 599→      });
 600→    }
 601→
 602→    case 'ASSEMBLY_REMOVE_PART': {
 603→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 604→      if (managedObject) return state;
 605→
 606→      return applyUpdate(state, {
 607→        ...state.project,
 608→        updatedAt: new Date().toISOString(),
 609→        assemblies: state.project.assemblies.map((assembly) => (
 610→          assembly.id === action.assemblyId
 611→            ? { ...assembly, partIds: assembly.partIds.filter((id) => id !== action.partId) }
 612→            : assembly
 613→        )),
 614→        parts: state.project.parts.map((part) => (
 615→          part.id === action.partId && part.assemblyId === action.assemblyId
 616→            ? { ...part, assemblyId: null }
 617→            : part
 618→        )),
 619→      });
 620→    }
 621→
 622→    case 'ASSEMBLY_CLONE': {
 623→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 624→      if (managedObject) return state;
 625→
 626→      const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
 627→      if (!assembly) return state;
 628→
 629→      const idMap = new Map();
 630→      const newAssemblyId = generateId('asm');
 631→      const newAssembly = {
 632→        ...assembly,
 633→        id: newAssemblyId,
 634→        name: `${assembly.name} (copy)`,
 635→        partIds: [],
 636→        objectId: assembly.objectId || null,
 637→        source: 'manual',
 638→      };
 639→
 640→      const assemblyParts = state.project.parts.filter((part) => part.assemblyId === action.assemblyId);
 641→      const clonedParts = [];
 642→
 643→      for (const part of assemblyParts) {
 644→        const cloned = clonePart(part, idMap);
 645→        cloned.assemblyId = newAssemblyId;
 646→        clonedParts.push(cloned);
 647→      }
 648→
 649→      for (const clonedPart of clonedParts) {
 650→        if (clonedPart.parentId && idMap.has(clonedPart.parentId)) {
 651→          clonedPart.parentId = idMap.get(clonedPart.parentId);
 652→        }
 653→      }
 654→
 655→      newAssembly.partIds = clonedParts.map((part) => part.id);
 656→
 657→      return applyUpdate(state, {
 658→        ...state.project,
 659→        updatedAt: new Date().toISOString(),
 660→        parts: [...state.project.parts, ...clonedParts],
 661→        assemblies: [...state.project.assemblies, newAssembly],
 662→      });
 663→    }
 664→
 665→    case 'OBJECT_UPDATE':
 666→      return applyUpdate(state, {
 667→        ...state.project,
 668→        updatedAt: new Date().toISOString(),
 669→        objects: (state.project.objects || []).map((object) => (
 670→          object.id === action.object.id
 671→            ? {
 672→                ...object,
 673→                ...action.object,
 674→                templateParams: action.object.templateParams
 675→                  ? { ...action.object.templateParams }
 676→                  : object.templateParams,
 677→                dimensions: action.object.dimensions
 678→                  ? { ...action.object.dimensions }
 679→                  : object.dimensions,
 680→                updatedAt: new Date().toISOString(),
 681→              }
 682→            : object
 683→        )),
 684→      });
 685→
 686→    case 'OBJECT_DELETE': {
 687→      const object = getManagedObject(state.project, action.objectId);
 688→      if (!object) return state;
 689→
 690→      const strippedProject = removeObjectArtifacts(state.project, object.id);
 691→      return applyUpdate(state, {
 692→        ...strippedProject,
 693→        updatedAt: new Date().toISOString(),
 694→        objects: (strippedProject.objects || []).filter((entry) => entry.id !== object.id),
 695→      });
 696→    }
 697→
 698→    case 'OBJECT_MOVE': {
 699→      const object = getManagedObject(state.project, action.objectId);
 700→      if (!object) return state;
 701→
 702→      const partIds = new Set(
 703→        state.project.parts.filter((part) => part.objectId === object.id).map((part) => part.id)
 704→      );
 705→
 706→      let nextProject = {
 707→        ...state.project,
 708→        updatedAt: new Date().toISOString(),
 709→        objects: state.project.objects.map((entry) => (
 710→          entry.id === object.id
 711→            ? {
 712→                ...entry,
 713→                origin: {
 714→                  x: entry.origin.x + (action.delta.dx || 0),
 715→                  y: entry.origin.y + (action.delta.dy || 0),
 716→                  z: entry.origin.z + (action.delta.dz || 0),
 717→                },
 718→                updatedAt: new Date().toISOString(),
 719→              }
 720→            : entry
 721→        )),
 722→        parts: state.project.parts.map((part) => {
 723→          if (!partIds.has(part.id) || part.type === 'dimension') return part;
 724→          return sanitizePart({
 725→            ...part,
 726→            position: {
 727→              x: part.position.x + (action.delta.dx || 0),
 728→              y: part.position.y + (action.delta.dy || 0),
 729→              z: part.position.z + (action.delta.dz || 0),
 730→            },
 731→          });
 732→        }),
 733→      };
 734→      nextProject = applyConstraints(nextProject);
 735→      for (const partId of partIds) {
 736→        nextProject = updateBoundDimensions(nextProject, partId);
 737→      }
 738→      return applyUpdate(state, nextProject);
 739→    }
 740→
 741→    case 'OBJECT_DETACH': {
 742→      const object = getManagedObject(state.project, action.objectId);
 743→      if (!object) return state;
 744→      return applyUpdate(state, {
 745→        ...detachManagedObject(state.project, object.id),
 746→        updatedAt: new Date().toISOString(),
 747→      });
 748→    }
 749→
 750→    case 'CONSTRAINT_ADD': {
 751→      const constraints = [...(state.project.constraints || []), action.constraint];
 752→      let nextProject = {
 753→        ...state.project,
 754→        updatedAt: new Date().toISOString(),
 755→        constraints,
 756→      };
 757→      nextProject = applyConstraints(nextProject);
 758→      return applyUpdate(state, nextProject);
 759→    }
 760→
 761→    case 'CONSTRAINT_UPDATE': {
 762→      const constraints = (state.project.constraints || []).map((constraint) => (
 763→        constraint.id === action.constraint.id ? { ...constraint, ...action.constraint } : constraint
 764→      ));
 765→      let nextProject = {
 766→        ...state.project,
 767→        updatedAt: new Date().toISOString(),
 768→        constraints,
 769→      };
 770→      nextProject = applyConstraints(nextProject);
 771→      return applyUpdate(state, nextProject);
 772→    }
 773→
 774→    case 'CONSTRAINT_DELETE': {
 775→      const constraints = (state.project.constraints || []).filter(
 776→        (constraint) => constraint.id !== action.constraintId
 777→      );
 778→      return applyUpdate(state, {
 779→        ...state.project,
 780→        updatedAt: new Date().toISOString(),
 781→        constraints,
 782→      });
 783→    }
 784→
 785→    case 'ANNOTATION_ADD':
 786→      return applyUpdate(state, {
 787→        ...state.project,
 788→        updatedAt: new Date().toISOString(),
 789→        annotations: [...(state.project.annotations || []), action.annotation],
 790→      });
 791→
 792→    case 'ANNOTATION_UPDATE':
 793→      return applyUpdate(state, {
 794→        ...state.project,
 795→        updatedAt: new Date().toISOString(),
 796→        annotations: (state.project.annotations || []).map((annotation) => (
 797→          annotation.id === action.annotation.id ? { ...annotation, ...action.annotation } : annotation
 798→        )),
 799→      });
 800→
 801→    case 'ANNOTATION_DELETE':
 802→      return applyUpdate(state, {
 803→        ...state.project,
 804→        updatedAt: new Date().toISOString(),
 805→        annotations: (state.project.annotations || []).filter((annotation) => annotation.id !== action.annotationId),
 806→      });
 807→
 808→    case 'PROJECT_UPDATE_META':
 809→      return applyUpdate(state, {
 810→        ...state.project,
 811→        updatedAt: new Date().toISOString(),
 812→        ...action.meta,
 813→      });
 814→
 815→    case 'SKETCH_SHEET_ADD':
 816→      return applyUpdate(state, {
 817→        ...state.project,
 818→        updatedAt: new Date().toISOString(),
 819→        sheets: [...(state.project.sheets || []), action.sheet],
 820→      });
 821→
 822→    case 'SKETCH_SHEET_UPDATE':
 823→      return applyUpdate(state, {
 824→        ...state.project,
 825→        updatedAt: new Date().toISOString(),
 826→        sheets: (state.project.sheets || []).map((sheet) => (
 827→          sheet.id === action.sheet.id ? { ...sheet, ...action.sheet } : sheet
 828→        )),
 829→      });
 830→
 831→    case 'SKETCH_SHEET_DELETE':
 832→      return applyUpdate(state, {
 833→        ...state.project,
 834→        updatedAt: new Date().toISOString(),
 835→        sheets: (state.project.sheets || []).filter((sheet) => sheet.id !== action.sheetId),
 836→      });
 837→
 838→    case 'SKETCH_SHEET_VIEWPORT_ADD': {
 839→      const targetSheet = (state.project.sheets || []).find((sheet) => sheet.id === action.sheetId);
 840→      if (!targetSheet) return state;
 841→      return applyUpdate(state, {
 842→        ...state.project,
 843→        updatedAt: new Date().toISOString(),
 844→        sheets: state.project.sheets.map((sheet) => (
 845→          sheet.id === action.sheetId
 846→            ? { ...sheet, viewports: [...(sheet.viewports || []), action.viewport] }
 847→            : sheet
 848→        )),
 849→      });
 850→    }
 851→
 852→    case 'SKETCH_SHEET_VIEWPORT_UPDATE':
 853→      return applyUpdate(state, {
 854→        ...state.project,
 855→        updatedAt: new Date().toISOString(),
 856→        sheets: (state.project.sheets || []).map((sheet) => (
 857→          sheet.id === action.sheetId
 858→            ? {
 859→                ...sheet,
 860→                viewports: (sheet.viewports || []).map((viewport) => (
 861→                  viewport.id === action.viewport.id ? { ...viewport, ...action.viewport } : viewport
 862→                )),
 863→              }
 864→            : sheet
 865→        )),
 866→      });
 867→
 868→    case 'SKETCH_SHEET_VIEWPORT_DELETE':
 869→      return applyUpdate(state, {
 870→        ...state.project,
 871→        updatedAt: new Date().toISOString(),
 872→        sheets: (state.project.sheets || []).map((sheet) => (
 873→          sheet.id === action.sheetId
 874→            ? { ...sheet, viewports: (sheet.viewports || []).filter((viewport) => viewport.id !== action.viewportId) }
 875→            : sheet
 876→        )),
 877→      });
 878→
 879→    case 'TEMPLATE_GENERATE': {
 880→      const generated = generateObjectFromTemplate(action.templateType, action.params, {
 881→        objectId: action.objectId,
 882→        name: action.name,
 883→        origin: action.origin,
 884→      });
 885→      return applyUpdate(state, {
 886→        ...addGeneratedObject(state.project, generated),
 887→        updatedAt: new Date().toISOString(),
 888→      });
 889→    }
 890→
 891→    case 'TEMPLATE_REGENERATE': {
 892→      const object = action.objectId
 893→        ? getManagedObject(state.project, action.objectId)
 894→        : getManagedObjectForAssembly(state.project, action.assemblyId);
 895→      if (!object || !object.templateType) return state;
 896→
 897→      const nextProject = rebuildManagedObject(state.project, object, action.params);
 898→      return applyUpdate(state, {
 899→        ...nextProject,
 900→        updatedAt: new Date().toISOString(),
 901→      });
 902→    }
 903→
 904→    case 'TEMPLATE_DETACH': {
 905→      const object = action.objectId
 906→        ? getManagedObject(state.project, action.objectId)
 907→        : getManagedObjectForAssembly(state.project, action.assemblyId);
 908→      if (!object) return state;
 909→      return sketchReducer(state, { type: 'OBJECT_DETACH', objectId: object.id });
 910→    }
 911→
 912→    case 'UNDO': {
 913→      if (state.history.length === 0) return state;
 914→      const previous = state.history[state.history.length - 1];
 915→      return {
 916→        ...state,
 917→        project: previous,
 918→        history: state.history.slice(0, -1),
 919→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
 920→        isDirty: snapshotSketch(previous) !== state.savedSnapshot,
 921→      };
 922→    }
 923→
 924→    case 'REDO': {
 925→      if (state.future.length === 0) return state;
 926→      const next = state.future[0];
 927→      return {
 928→        ...state,
 929→        project: next,
 930→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
 931→        future: state.future.slice(1),
 932→        isDirty: snapshotSketch(next) !== state.savedSnapshot,
 933→      };
 934→    }
 935→
 936→    case 'MARK_SAVED':
 937→      return {
 938→        ...state,
 939→        isDirty: false,
 940→        savedSnapshot: snapshotSketch(state.project),
 941→      };
 942→
 943→    default:
 944→      return state;
 945→  }
 946→}
