 17→      id: part.id,
 18→      partId: part.id,
 19→      role: part.role || part.generatedRole || part.type,
 20→      name: part.name,
 21→    }));
 22→
 23→  return {
 24→    kind: 'assembly',
 25→    id: assembly.id,
 26→    assemblyId: assembly.id,
 27→    name: assembly.name,
 28→    role: assembly.role || 'legacy_root',
 29→    description: assembly.description || '',
 30→    children: partNodes,
 31→  };
 32→}
