  1→import { projectPartToView } from '../../domain/viewProjection';
  2→import { projectDimensionPoint } from '../../renderers/DimensionRenderer';
  3→import { createDimensionFigure, hitTestDimensionFigure } from '@/annotations/dimensions';
  4→import { snapPoint } from '../snap';
  5→import { SKETCH_GRID_MINOR } from '../../domain/defaults';
  6→
  7→export function createSketchSelectHandler({ dispatch, editorDispatch, project, activeView, viewport, snapEnabled, activeAssemblyId, selectedId, selectedType }) {
  8→  function hitTestDimensions(modelPos) {
  9→    const tolerance = 8 / viewport.zoom;
 10→    const dims = project.parts.filter((p) => p.type === 'dimension');
 11→
 12→    for (let i = dims.length - 1; i >= 0; i--) {
 13→      const dim = dims[i];
 14→      const start2D = projectDimensionPoint(dim.startPoint, activeView);
 15→      const end2D = projectDimensionPoint(dim.endPoint, activeView);
 16→
 17→      const figure = createDimensionFigure({
 18→        id: dim.id,
 19→        startPoint: start2D,
 20→        endPoint: end2D,
 21→        mode: 'aligned',
 22→        offset: dim.offset || 200,
 23→        source: 'manual',
 24→      });
 25→
 26→      if (figure && hitTestDimensionFigure(modelPos, figure, tolerance)) {
 27→        return { id: dim.id, type: 'part' };
 28→      }
 29→    }
 30→    return null;
 31→  }
 32→
 33→  function hitTestParts(modelPos, filterFn) {
 34→    const tolerance = 6 / viewport.zoom;
 35→    const parts = project.parts.filter((p) => p.type !== 'dimension' && (!filterFn || filterFn(p)));
 36→
 37→    for (let i = parts.length - 1; i >= 0; i--) {
 38→      const part = parts[i];
 39→      const { svgX, svgY, svgWidth, svgHeight } = projectPartToView(part, activeView);
 40→
 41→      if (
 42→        modelPos.x >= svgX - tolerance &&
 43→        modelPos.x <= svgX + svgWidth + tolerance &&
 44→        modelPos.y >= svgY - tolerance &&
 45→        modelPos.y <= svgY + svgHeight + tolerance
 46→      ) {
 47→        return part;
 48→      }
 49→    }
 50→    return null;
 51→  }
 52→
 53→  function computeViewDelta(dx, dy) {
 54→    switch (activeView) {
 55→      case 'top':
 56→        return { dx, dy, dz: 0 };
 57→      case 'front':
 58→        return { dx, dy: 0, dz: -dy };
 59→      case 'side':
 60→        return { dx: 0, dy: dx, dz: -dy };
 61→      default:
 62→        return { dx, dy, dz: 0 };
 63→    }
 64→  }
 65→
 66→  const isEditMode = activeAssemblyId !== null;
 67→
 68→  return {
 69→    onMouseDown(modelPos, e, toolState) {
 70→      if (e.button !== 0) return;
 71→
 72→      // Try dimensions first (they render on top)
 73→      const dimHit = hitTestDimensions(modelPos);
 74→      if (dimHit) {
 75→        editorDispatch({ type: 'SELECT_OBJECT', id: dimHit.id, objectType: dimHit.type });
 76→        return;
 77→      }
 78→
 79→      if (isEditMode) {
 80→        // Edit mode: only hit-test parts within the active assembly
 81→        const hitPart = hitTestParts(modelPos, (p) => p.assemblyId === activeAssemblyId);
 82→        if (hitPart) {
 83→          editorDispatch({ type: 'SELECT_OBJECT', id: hitPart.id, objectType: 'part' });
 84→          editorDispatch({
 85→            type: 'UPDATE_TOOL_STATE',
 86→            payload: { dragging: true, startPos: modelPos, dragPartId: hitPart.id },
 87→          });
 88→        } else {
 89→          editorDispatch({ type: 'DESELECT' });
 90→        }
 91→      } else {
 92→        // Normal mode: hit-test all parts
 93→        const hitPart = hitTestParts(modelPos);
 94→        if (hitPart) {
 95→          const parametricObject = hitPart.objectId
 96→            ? (project.objects || []).find((object) => object.id === hitPart.objectId && object.editingPolicy === 'parametric')
 97→            : null;
 98→
 99→          if (parametricObject) {
100→            editorDispatch({ type: 'SELECT_OBJECT', id: hitPart.objectId, objectType: 'object' });
101→            editorDispatch({
102→              type: 'UPDATE_TOOL_STATE',
103→              payload: { dragging: true, startPos: modelPos, dragObjectId: hitPart.objectId },
104→            });
105→          } else if (hitPart.assemblyId) {
106→            // Promote to assembly selection
107→            editorDispatch({ type: 'SELECT_OBJECT', id: hitPart.assemblyId, objectType: 'assembly' });
108→            editorDispatch({
109→              type: 'UPDATE_TOOL_STATE',
110→              payload: { dragging: true, startPos: modelPos, dragAssemblyId: hitPart.assemblyId },
111→            });
112→          } else {
113→            // Select individual part
114→            editorDispatch({ type: 'SELECT_OBJECT', id: hitPart.id, objectType: 'part' });
115→            editorDispatch({
116→              type: 'UPDATE_TOOL_STATE',
117→              payload: { dragging: true, startPos: modelPos, dragPartId: hitPart.id },
118→            });
119→          }
120→        } else {
121→          editorDispatch({ type: 'DESELECT' });
122→        }
123→      }
124→    },
125→
126→    onMouseMove(modelPos, e, toolState) {
127→      if (!toolState.dragging || !toolState.startPos) return;
128→
129→      const dx = modelPos.x - toolState.startPos.x;
130→      const dy = modelPos.y - toolState.startPos.y;
131→      if (Math.abs(dx) < 1 && Math.abs(dy) < 1) return;
132→
133→      // Assembly drag (normal mode)
134→      if (toolState.dragAssemblyId) {
135→        const delta = computeViewDelta(dx, dy);
136→
137→        // Snap the delta
138→        if (snapEnabled) {
139→          const snapped = snapPoint({ x: delta.dx, y: delta.dy }, SKETCH_GRID_MINOR);
140→          if (Math.abs(snapped.x) < 1 && Math.abs(snapped.y) < 1) return;
141→          // Recompute full 3D delta from snapped 2D
142→          const snappedDelta = computeViewDelta(snapped.x, snapped.y);
143→          dispatch({
144→            type: 'ASSEMBLY_MOVE',
145→            assemblyId: toolState.dragAssemblyId,
146→            delta: snappedDelta,
147→          });
148→        } else {
149→          dispatch({
150→            type: 'ASSEMBLY_MOVE',
151→            assemblyId: toolState.dragAssemblyId,
152→            delta,
153→          });
154→        }
155→
156→        editorDispatch({
157→          type: 'UPDATE_TOOL_STATE',
158→          payload: { startPos: modelPos },
159→        });
160→        return;
161→      }
162→
163→      if (toolState.dragObjectId) {
164→        const delta = computeViewDelta(dx, dy);
165→        if (snapEnabled) {
166→          const snapped = snapPoint({ x: delta.dx, y: delta.dy }, SKETCH_GRID_MINOR);
167→          if (Math.abs(snapped.x) < 1 && Math.abs(snapped.y) < 1) return;
168→          dispatch({
169→            type: 'OBJECT_MOVE',
170→            objectId: toolState.dragObjectId,
171→            delta: computeViewDelta(snapped.x, snapped.y),
172→          });
173→        } else {
174→          dispatch({
175→            type: 'OBJECT_MOVE',
176→            objectId: toolState.dragObjectId,
177→            delta,
178→          });
179→        }
180→
181→        editorDispatch({
182→          type: 'UPDATE_TOOL_STATE',
183→          payload: { startPos: modelPos },
184→        });
185→        return;
186→      }
187→
188→      // Individual part drag (edit mode or unassigned part)
189→      if (toolState.dragPartId) {
190→        const part = project.parts.find((p) => p.id === toolState.dragPartId);
191→        if (!part || part.type === 'dimension') return;
192→
193→        const pos = { ...part.position };
194→        switch (activeView) {
195→          case 'top':
196→            pos.x += dx;
197→            pos.y += dy;
198→            break;
199→          case 'front':
200→            pos.x += dx;
201→            pos.z -= dy;
202→            break;
203→          case 'side':
204→            pos.y += dx;
205→            pos.z -= dy;
206→            break;
207→        }
208→
209→        if (snapEnabled) {
210→          const snapped = snapPoint(pos, SKETCH_GRID_MINOR);
211→          pos.x = snapped.x;
212→          pos.y = snapped.y;
213→        }
214→
215→        dispatch({
216→          type: 'PART_UPDATE',
217→          part: { id: toolState.dragPartId, position: pos },
218→        });
219→
220→        editorDispatch({
221→          type: 'UPDATE_TOOL_STATE',
222→          payload: { startPos: modelPos },
223→        });
224→      }
225→    },
226→
227→    onMouseUp(modelPos, e, toolState) {
228→      if (toolState.dragging) {
229→        editorDispatch({
230→          type: 'UPDATE_TOOL_STATE',
231→          payload: { dragging: false, startPos: null, dragPartId: null, dragAssemblyId: null, dragObjectId: null },
232→        });
233→      }
234→    },
235→
236→    onDoubleClick(modelPos, e, toolState) {
237→      if (isEditMode) return;
238→
239→      // In normal mode: if we hit a part that belongs to an assembly, enter edit mode
240→      const hitPart = hitTestParts(modelPos);
241→      const parametricObject = hitPart?.objectId
242→        ? (project.objects || []).find((object) => object.id === hitPart.objectId && object.editingPolicy === 'parametric')
243→        : null;
244→      if (hitPart && hitPart.assemblyId && !parametricObject) {
245→        editorDispatch({ type: 'ENTER_ASSEMBLY_EDIT', assemblyId: hitPart.assemblyId });
246→      }
247→    },
248→
249→    onKeyDown(e, toolState, currentSelectedId) {
250→      // Escape in edit mode: exit edit mode
251→      if (e.key === 'Escape' && isEditMode) {
252→        e.preventDefault();
253→        e.stopPropagation();
254→        // Exit edit mode, re-select the assembly
255→        editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: null });
256→        return;
257→      }
258→
259→      if ((e.key === 'Delete' || e.key === 'Backspace') && currentSelectedId) {
260→        if (selectedType === 'object') {
261→          dispatch({ type: 'OBJECT_DELETE', objectId: currentSelectedId });
262→        } else if (selectedType === 'assembly' && !isEditMode) {
263→          // Delete assembly with all its parts
264→          dispatch({ type: 'ASSEMBLY_DELETE_WITH_PARTS', assemblyId: currentSelectedId });
265→        } else {
266→          // Delete individual part
267→          dispatch({ type: 'PART_DELETE', partId: currentSelectedId });
268→        }
269→        editorDispatch({ type: 'DESELECT' });
270→      }
271→    },
272→
273→    getCursor(toolState) {
274→      if (toolState?.dragging) return 'grabbing';
275→      return 'default';
276→    },
277→  };
278→}
