 175→
 176→  const handleBind = (partId, property) => {
 177→    const target = project.parts.find((p) => p.id === partId);
 178→    if (!target) return;
 179→    const updated = bindDimensionToPart(part, target, property);
 180→    dispatch({ type: 'PART_UPDATE', part: { id: part.id, ...updated } });
 181→  };
