  1→import { createDimensionFigure } from '@/annotations/dimensions';
  2→import { getPartExtents, projectPartToView } from './viewProjection';
  3→
  4→const PART_PADDING = 500;
  5→const VIEW_GAP = 300;
  6→
  7→function projectDimensionPoint(point, view) {
  8→  switch (view) {
  9→    case 'top':
 10→      return { x: point.x, y: point.y };
 11→    case 'front':
 12→      return { x: point.x, y: -(point.z || 0) };
 13→    case 'side':
 14→      return { x: point.y, y: -(point.z || 0) };
 15→    default:
 16→      return { x: point.x, y: point.y };
 17→  }
 18→}
 19→
 20→function getPartsBounds(parts, view, dimensions = []) {
 21→  let minX = Infinity;
 22→  let minY = Infinity;
 23→  let maxX = -Infinity;
 24→  let maxY = -Infinity;
 25→
 26→  for (const part of parts) {
 27→    if (part.type === 'dimension') continue;
 28→    const { svgX, svgY, svgWidth, svgHeight } = projectPartToView(part, view);
 29→    minX = Math.min(minX, svgX);
 30→    minY = Math.min(minY, svgY);
 31→    maxX = Math.max(maxX, svgX + svgWidth);
 32→    maxY = Math.max(maxY, svgY + svgHeight);
 33→  }
 34→
 35→  for (const dim of dimensions) {
 36→    const start2D = projectDimensionPoint(dim.startPoint, view);
 37→    const end2D = projectDimensionPoint(dim.endPoint, view);
 38→    const figure = createDimensionFigure({
 39→      id: dim.id,
 40→      startPoint: start2D,
 41→      endPoint: end2D,
 42→      mode: 'aligned',
 43→      offset: dim.offset || 200,
 44→      label: dim.textOverride || undefined,
 45→      source: 'manual',
 46→    });
 47→    if (!figure) continue;
 48→    const points = [
 49→      figure.lineStart,
 50→      figure.lineEnd,
 51→      ...figure.extensionLines.flatMap((line) => [line.start, line.end]),
 52→    ];
 53→    for (const point of points) {
 54→      minX = Math.min(minX, point.x);
 55→      minY = Math.min(minY, point.y);
 56→      maxX = Math.max(maxX, point.x);
 57→      maxY = Math.max(maxY, point.y);
 58→    }
 59→  }
 60→
 61→  if (minX === Infinity) return { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
 62→  return {
 63→    minX: minX - PART_PADDING,
 64→    maxX: maxX + PART_PADDING,
 65→    minY: minY - PART_PADDING,
 66→    maxY: maxY + PART_PADDING,
 67→  };
 68→}
 69→
 70→function resolveObject(project, objectId) {
 71→  if (!objectId) return null;
 72→  return (project.objects || []).find((object) => object.id === objectId) || null;
 73→}
 74→
 75→function resolveAssembly(project, assemblyId) {
 76→  if (!assemblyId) return null;
 77→  return (project.assemblies || []).find((assembly) => assembly.id === assemblyId) || null;
 78→}
 79→
 80→function gatherObjectParts(project, objectId) {
 81→  if (!objectId) {
 82→    return project.parts.filter((part) => part.type !== 'dimension');
 83→  }
 84→  return project.parts.filter((part) => part.objectId === objectId && part.type !== 'dimension');
 85→}
 86→
 87→function gatherObjectDimensions(project, objectId) {
 88→  if (!objectId) {
 89→    return project.parts.filter((part) => part.type === 'dimension');
 90→  }
 91→
 92→  const partIds = new Set(project.parts.filter((part) => part.objectId === objectId).map((part) => part.id));
 93→  return project.parts.filter((part) => part.type === 'dimension' && part.boundPartId && partIds.has(part.boundPartId));
 94→}
 95→
 96→function gatherAssemblyParts(project, assemblyId) {
 97→  if (!assemblyId) return gatherObjectParts(project, null);
 98→  return project.parts.filter((part) => part.assemblyId === assemblyId && part.type !== 'dimension');
 99→}
100→
101→function gatherAssemblyDimensions(project, assemblyId) {
102→  if (!assemblyId) return gatherObjectDimensions(project, null);
103→  const partIds = new Set(project.parts.filter((part) => part.assemblyId === assemblyId).map((part) => part.id));
104→  return project.parts.filter((part) => part.type === 'dimension' && part.boundPartId && partIds.has(part.boundPartId));
105→}
106→
107→function resolveObjectName(project, objectId) {
108→  return resolveObject(project, objectId)?.name || project.name || 'All Objects';
109→}
110→
111→function resolveAssemblyName(project, assemblyId) {
112→  return resolveAssembly(project, assemblyId)?.name || project.name || 'Assembly';
113→}
114→
115→export function buildObjectDraftSource(project, objectId, view) {
116→  const parts = gatherObjectParts(project, objectId);
117→  const dimensions = gatherObjectDimensions(project, objectId);
118→
119→  if (parts.length === 0) {
120→    return {
121→      kind: 'empty',
122→      title: `${resolveObjectName(project, objectId)} — ${view}`,
123→      message: 'No parts in this object.',
124→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
125→    };
126→  }
127→
128→  return {
129→    kind: 'sketch_object',
130→    title: `${resolveObjectName(project, objectId)} — ${view}`,
131→    view,
132→    parts,
133→    dimensions,
134→    object: resolveObject(project, objectId),
135→    bounds: getPartsBounds(parts, view, dimensions),
136→  };
137→}
138→
139→export function buildAssemblyDraftSource(project, assemblyId, view) {
140→  const parts = gatherAssemblyParts(project, assemblyId);
141→  const dimensions = gatherAssemblyDimensions(project, assemblyId);
142→
143→  if (parts.length === 0) {
144→    return {
145→      kind: 'empty',
146→      title: `${resolveAssemblyName(project, assemblyId)} — ${view}`,
147→      message: 'No parts in this assembly.',
148→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
149→    };
150→  }
151→
152→  return {
153→    kind: 'sketch_assembly',
154→    title: `${resolveAssemblyName(project, assemblyId)} — ${view}`,
155→    view,
156→    parts,
157→    dimensions,
158→    assembly: resolveAssembly(project, assemblyId),
159→    bounds: getPartsBounds(parts, view, dimensions),
160→  };
161→}
162→
163→export function buildPartDetailSource(project, partId) {
164→  const part = project.parts.find((entry) => entry.id === partId);
165→  if (!part || part.type === 'dimension') {
166→    return {
167→      kind: 'empty',
168→      title: 'Part Detail',
169→      message: 'Part not found.',
170→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
171→    };
172→  }
173→
174→  const extents = getPartExtents(part);
175→  const views = ['top', 'front', 'side'];
176→  const viewBounds = views.map((view) => {
177→    const { svgX, svgY, svgWidth, svgHeight } = projectPartToView(part, view);
178→    return { view, svgX, svgY, svgWidth, svgHeight };
179→  });
180→
181→  let offsetX = 0;
182→  const viewLayouts = [];
183→
184→  for (const viewBound of viewBounds) {
185→    viewLayouts.push({
186→      view: viewBound.view,
187→      offsetX,
188→      offsetY: 0,
189→      width: viewBound.svgWidth,
190→      height: viewBound.svgHeight,
191→      svgX: viewBound.svgX,
192→      svgY: viewBound.svgY,
193→    });
194→    offsetX += viewBound.svgWidth + VIEW_GAP;
195→  }
196→
197→  const maxHeight = Math.max(...viewBounds.map((viewBound) => viewBound.svgHeight));
198→
199→  return {
200→    kind: 'sketch_part_detail',
201→    title: part.name || 'Part Detail',
202→    part,
203→    extents,
204→    viewLayouts,
205→    bounds: {
206→      minX: -PART_PADDING,
207→      maxX: offsetX - VIEW_GAP + PART_PADDING,
208→      minY: -PART_PADDING,
209→      maxY: maxHeight + PART_PADDING,
210→    },
211→  };
212→}
213→
214→export function buildPartListSource(project, scope = {}) {
215→  const parts = scope.objectId
216→    ? gatherObjectParts(project, scope.objectId)
217→    : scope.assemblyId
218→      ? gatherAssemblyParts(project, scope.assemblyId)
219→      : gatherObjectParts(project, null);
220→
221→  const groupMap = new Map();
222→  for (const part of parts) {
223→    const extents = getPartExtents(part);
224→    const key = `${part.type}|${part.material || ''}|${extents.width}|${extents.depth}|${extents.height}`;
225→    if (groupMap.has(key)) {
226→      groupMap.get(key).qty += 1;
227→    } else {
228→      groupMap.set(key, {
229→        name: part.name,
230→        type: part.type,
231→        material: part.material || '-',
232→        width: extents.width,
233→        depth: extents.depth,
234→        height: extents.height,
235→        qty: 1,
236→      });
237→    }
238→  }
239→
240→  const rows = [];
241→  let item = 1;
242→  for (const group of groupMap.values()) {
243→    rows.push({
244→      item,
245→      name: group.name,
246→      type: group.type,
247→      material: group.material,
248→      qty: group.qty,
249→      dims: `${Math.round(group.width)} x ${Math.round(group.depth)} x ${Math.round(group.height)}`,
250→    });
251→    item += 1;
252→  }
253→
254→  const columnWidths = [30, 120, 60, 80, 30, 120];
255→  const tableWidth = columnWidths.reduce((sum, width) => sum + width, 0);
256→  const rowHeight = 20;
257→  const headerHeight = 24;
258→  const tableHeight = headerHeight + rows.length * rowHeight;
259→
260→  const title = scope.objectId
261→    ? `${resolveObjectName(project, scope.objectId)} Parts List`
262→    : scope.assemblyId
263→      ? `${resolveAssemblyName(project, scope.assemblyId)} Parts List`
264→      : `${project.name || 'Sketch'} Parts List`;
265→
266→  return {
267→    kind: 'sketch_part_list',
268→    title,
269→    rows,
270→    columnWidths,
271→    headers: ['Item', 'Name', 'Type', 'Material', 'Qty', 'Dimensions'],
272→    rowHeight,
273→    headerHeight,
274→    bounds: {
275→      minX: 0,
276→      maxX: tableWidth,
277→      minY: 0,
278→      maxY: tableHeight,
279→    },
280→  };
281→}
