119→export default function SketchSidebar() {
120→  const { project, dispatch } = useSketch();
121→  const {
122→    activeAssemblyId,
123→    selectedId,
124→    selectedType,
125→    workspaceMode,
126→    activeSheetId,
127→    dispatch: editorDispatch,
128→  } = useSketchEditor();
129→  const { setShowTemplateDialog } = useSketchProject();
130→  const [expandedIds, setExpandedIds] = useState(new Set());
131→
132→  const objects = project.objects || [];
133→  const objectTrees = useMemo(
134→    () => objects.map((object) => ({ object, tree: buildObjectTree(project, object) })),
135→    [objects, project]
136→  );
137→  const manualAssemblies = (project.assemblies || []).filter((assembly) => !assembly.objectId);
138→  const allParts = project.parts.filter((part) => part.type !== 'dimension');
139→  const manualParts = allParts.filter((part) => !part.objectId && !part.assemblyId);
140→  const sheets = project.sheets || [];
141→
142→  const toggleExpand = (id) => {
143→    setExpandedIds((prev) => {
144→      const next = new Set(prev);
145→      if (next.has(id)) next.delete(id);
146→      else next.add(id);
147→      return next;
148→    });
149→  };
150→
151→  const enterModelMode = () => {
152→    if (workspaceMode === 'sheet') {
153→      editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
154→    }
155→  };
156→
157→  const handleSelectObject = (objectId) => {
158→    enterModelMode();
159→    editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: null });
160→    editorDispatch({ type: 'SELECT_OBJECT', id: objectId, objectType: 'object' });
161→  };
162→
163→  const handleSelectAssembly = (assemblyId) => {
164→    enterModelMode();
165→    editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId });
166→    editorDispatch({ type: 'SELECT_OBJECT', id: assemblyId, objectType: 'assembly' });
167→  };
168→
169→  const handleSelectPart = (partId) => {
170→    enterModelMode();
171→    editorDispatch({ type: 'SELECT_OBJECT', id: partId, objectType: 'part' });
172→  };
173→
174→  const handleDeletePart = (partId) => {
175→    dispatch({ type: 'PART_DELETE', partId });
176→    if (selectedId === partId) editorDispatch({ type: 'DESELECT' });
177→  };
178→
179→  const handleClonePart = (partId) => {
180→    dispatch({ type: 'PART_CLONE', partId });
181→  };
182→
183→  const handleDeleteObject = (objectId) => {
184→    dispatch({ type: 'OBJECT_DELETE', objectId });
185→    const selectedAssembly = selectedType === 'assembly'
186→      ? project.assemblies.find((assembly) => assembly.id === selectedId)
187→      : null;
188→    const selectedPart = selectedType === 'part'
189→      ? project.parts.find((part) => part.id === selectedId)
190→      : null;
191→    if (
192→      selectedId === objectId
193→      || selectedAssembly?.objectId === objectId
194→      || selectedPart?.objectId === objectId
195→    ) {
196→      editorDispatch({ type: 'DESELECT' });
197→      editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: null });
198→    }
199→  };
200→
201→  const handleDetachObject = (objectId) => {
202→    dispatch({ type: 'OBJECT_DETACH', objectId });
203→    editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: null });
204→    if (selectedId === objectId) {
205→      editorDispatch({ type: 'DESELECT' });
206→    }
207→  };
208→
209→  const handleGenerateObjectSheet = (objectId) => {
210→    const sheet = generateObjectSheet(project, objectId);
211→    dispatch({ type: 'SKETCH_SHEET_ADD', sheet });
212→    editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
213→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
214→  };
215→
216→  const handleAddAssembly = () => {
217→    const assembly = createAssembly(`Assembly ${manualAssemblies.length + 1}`);
218→    dispatch({ type: 'ASSEMBLY_ADD', assembly });
219→    editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: assembly.id });
220→    editorDispatch({ type: 'SELECT_OBJECT', id: assembly.id, objectType: 'assembly' });
221→  };
222→
223→  const handleDeleteAssembly = (assemblyId) => {
224→    dispatch({ type: 'ASSEMBLY_DELETE', assemblyId });
225→    if (activeAssemblyId === assemblyId || selectedId === assemblyId) {
226→      editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: null });
227→      editorDispatch({ type: 'DESELECT' });
228→    }
229→  };
230→
231→  const handleCloneAssembly = (assemblyId) => {
232→    dispatch({ type: 'ASSEMBLY_CLONE', assemblyId });
233→  };
234→
235→  const handleGenerateAssemblySheet = (assemblyId) => {
236→    const sheet = generateAssemblySheet(project, assemblyId);
237→    dispatch({ type: 'SKETCH_SHEET_ADD', sheet });
238→    editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
239→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
240→  };
241→
242→  const handleAddSheet = () => {
243→    const sheet = createSheet(`Sheet ${sheets.length + 1}`, {
244→      number: `S${String(sheets.length + 1).padStart(2, '0')}`,
245→      drawingName: `Sheet ${sheets.length + 1}`,
246→    });
247→    dispatch({ type: 'SKETCH_SHEET_ADD', sheet });
248→    editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
249→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
250→  };
251→
252→  const renderGeneratedNode = (node, objectId, depth = 0) => {
253→    const object = objects.find((entry) => entry.id === objectId);
254→    if (!node) return null;
255→    if (node.kind === 'assembly') {
256→      const isExpanded = expandedIds.has(node.id);
257→      const isSelected = selectedType === 'assembly' && selectedId === node.assemblyId;
258→      const childCount = (node.children || []).length;
259→      return (
260→        <div key={node.id}>
261→          <TreeItem depth={depth} isSelected={isSelected} onClick={() => handleSelectAssembly(node.assemblyId)}>
262→            <div className={styles.layerInfo}>
263→              <button className={styles.expandBtn} onClick={(event) => { event.stopPropagation(); toggleExpand(node.id); }} aria-label={isExpanded ? 'Collapse' : 'Expand'}>
264→                <ChevronIcon expanded={isExpanded} />
265→              </button>
266→              <AssemblyIcon />
267→              <span className={styles.layerName}>{node.name}</span>
268→              {childCount > 0 && <span className={styles.shapeCount}>{childCount}</span>}
269→            </div>
270→          </TreeItem>
271→          {isExpanded && node.children?.length > 0 && (
272→            <div className={styles.indent}>
273→              {node.children.map((child) => renderGeneratedNode(child, objectId, depth + 1))}
274→            </div>
275→          )}
276→        </div>
277→      );
278→    }
279→
280→    const part = project.parts.find((entry) => entry.id === node.partId);
281→    if (!part) return null;
282→    return (
283→      <PartItem
284→        key={node.id}
285→        part={part}
286→        depth={depth}
287→        isSelected={selectedType === 'part' && selectedId === part.id}
288→        onSelect={handleSelectPart}
289→        onDelete={handleDeletePart}
290→        onClone={handleClonePart}
291→        allowActions={object?.editingPolicy !== 'parametric'}
292→      />
293→    );
294→  };
295→
296→  const renderManualAssemblyParts = (assemblyId, depth = 1) => {
297→    const parts = allParts.filter((part) => part.assemblyId === assemblyId && !part.objectId);
298→    return parts.map((part) => (
299→      <PartItem
300→        key={part.id}
301→        part={part}
302→        depth={depth}
303→        isSelected={selectedType === 'part' && selectedId === part.id}
304→        onSelect={handleSelectPart}
305→        onDelete={handleDeletePart}
306→        onClone={handleClonePart}
307→      />
308→    ));
309→  };
310→
311→  return (
312→    <div className={styles.sidebar}>
313→      <div className={styles.section}>
314→        <div className={styles.sectionHeaderRow}>
315→          <span className={styles.sectionTitle}>Objects</span>
316→          <span className={styles.count}>{objects.length}</span>
317→          <button className={styles.addBtn} onClick={() => setShowTemplateDialog(true)} aria-label="Create Object" title="Create Object">
318→            <TemplateIcon />
319→          </button>
320→        </div>
321→
322→        <div className={styles.layerList}>
323→          {objectTrees.map(({ object, tree }) => {
324→            const isExpanded = expandedIds.has(object.id);
325→            const isSelected = selectedType === 'object' && selectedId === object.id;
326→            return (
327→              <div key={object.id}>
328→                <TreeItem depth={0} isSelected={isSelected} onClick={() => handleSelectObject(object.id)}>
329→                  <div className={styles.layerInfo}>
330→                    <button className={styles.expandBtn} onClick={(event) => { event.stopPropagation(); toggleExpand(object.id); }} aria-label={isExpanded ? 'Collapse' : 'Expand'}>
331→                      <ChevronIcon expanded={isExpanded} />
332→                    </button>
333→                    <ObjectIcon />
334→                    <span className={styles.layerName}>{object.name}</span>
335→                    <span className={styles.categoryBadge}>{object.templateType || object.category}</span>
336→                    <span className={styles.shapeCount}>{object.partIds.length}</span>
337→                  </div>
338→                  <div className={styles.layerActions}>
339→                    <button className={styles.layerActionBtn} onClick={(event) => { event.stopPropagation(); handleGenerateObjectSheet(object.id); }} aria-label="Generate Object Sheet" title="Generate Object Sheet">
340→                      <SheetIcon />
341→                    </button>
342→                    {object.editingPolicy === 'parametric' && (
343→                      <button className={styles.layerActionBtn} onClick={(event) => { event.stopPropagation(); handleDetachObject(object.id); }} aria-label="Detach Object" title="Detach Object">
344→                        <CloneIcon />
345→                      </button>
346→                    )}
347→                    <button className={styles.layerActionBtn} onClick={(event) => { event.stopPropagation(); handleDeleteObject(object.id); }} aria-label="Delete Object" title="Delete Object">
348→                      <TrashIcon />
349→                    </button>
350→                  </div>
351→                </TreeItem>
352→                {isExpanded && tree?.children?.length > 0 && (
353→                  <div className={styles.indent}>
354→                    {tree.children.map((child) => renderGeneratedNode(child, object.id, 1))}
355→                  </div>
356→                )}
357→              </div>
358→            );
359→          })}
360→        </div>
361→      </div>
362→
363→      <div className={styles.section}>
364→        <div className={styles.sectionHeaderRow}>
365→          <span className={styles.sectionTitle}>Custom Assemblies</span>
366→          <span className={styles.count}>{manualAssemblies.length}</span>
367→          <button className={styles.addBtn} onClick={handleAddAssembly} aria-label="Add Assembly" title="Add Assembly">+</button>
368→        </div>
369→
370→        <div className={styles.layerList}>
371→          {manualAssemblies.map((assembly) => {
372→            const isExpanded = expandedIds.has(assembly.id);
373→            const isSelected = selectedType === 'assembly' && selectedId === assembly.id;
374→            const partCount = allParts.filter((part) => part.assemblyId === assembly.id).length;
375→            return (
376→              <div key={assembly.id}>
377→                <TreeItem depth={0} isSelected={isSelected} onClick={() => handleSelectAssembly(assembly.id)}>
378→                  <div className={styles.layerInfo}>
379→                    <button className={styles.expandBtn} onClick={(event) => { event.stopPropagation(); toggleExpand(assembly.id); }} aria-label={isExpanded ? 'Collapse' : 'Expand'}>
380→                      <ChevronIcon expanded={isExpanded} />
381→                    </button>
382→                    <AssemblyIcon />
383→                    <span className={styles.layerName}>{assembly.name}</span>
384→                    {partCount > 0 && <span className={styles.shapeCount}>{partCount}</span>}
385→                  </div>
386→                  <div className={styles.layerActions}>
387→                    <button className={styles.layerActionBtn} onClick={(event) => { event.stopPropagation(); handleGenerateAssemblySheet(assembly.id); }} aria-label="Generate Assembly Sheet" title="Generate Assembly Sheet">
388→                      <SheetIcon />
389→                    </button>
390→                    <button className={styles.layerActionBtn} onClick={(event) => { event.stopPropagation(); handleCloneAssembly(assembly.id); }} aria-label="Duplicate Assembly" title="Duplicate Assembly">
391→                      <CloneIcon />
392→                    </button>
393→                    <button className={styles.layerActionBtn} onClick={(event) => { event.stopPropagation(); handleDeleteAssembly(assembly.id); }} aria-label="Delete Assembly" title="Delete Assembly">
394→                      <TrashIcon />
395→                    </button>
396→                  </div>
397→                </TreeItem>
398→                {isExpanded && (
399→                  <div className={styles.indent}>
400→                    {renderManualAssemblyParts(assembly.id)}
401→                  </div>
402→                )}
403→              </div>
404→            );
405→          })}
406→        </div>
407→      </div>
408→
409→      <div className={styles.section}>
410→        <div className={styles.sectionHeaderRow}>
411→          <span className={styles.sectionTitle}>Draft Parts</span>
412→          <span className={styles.count}>{manualParts.length}</span>
413→        </div>
414→
415→        <div className={styles.layerList}>
416→          {manualParts.map((part) => (
417→            <PartItem
418→              key={part.id}
419→              part={part}
420→              depth={0}
421→              isSelected={selectedType === 'part' && selectedId === part.id}
422→              onSelect={handleSelectPart}
423→              onDelete={handleDeletePart}
424→              onClone={handleClonePart}
425→            />
426→          ))}
427→        </div>
428→      </div>
429→
430→      <div className={styles.section}>
431→        <div className={styles.sectionHeaderRow}>
432→          <span className={styles.sectionTitle}>Sheets</span>
433→          <span className={styles.count}>{sheets.length}</span>
434→          <button className={styles.addBtn} onClick={handleAddSheet} aria-label="Add Sheet" title="Add Sheet">+</button>
435→        </div>
436→
437→        <div className={styles.layerList}>
438→          {sheets.map((sheet) => {
439→            const isSelected = workspaceMode === 'sheet' && activeSheetId === sheet.id;
440→            return (
441→              <TreeItem
442→                key={sheet.id}
443→                depth={0}
444→                isSelected={isSelected}
445→                onClick={() => {
446→                  editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
447→                  editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
448→                }}
449→              >
450→                <div className={styles.layerInfo}>
451→                  <SheetIcon />
452→                  <span className={styles.layerName}>{sheet.title || sheet.drawingName || 'Sheet'}</span>
453→                  {(sheet.viewports || []).length > 0 && <span className={styles.shapeCount}>{sheet.viewports.length}v</span>}
454→                </div>
455→                <div className={styles.layerActions}>
456→                  <button className={styles.layerActionBtn} onClick={(event) => {
457→                    event.stopPropagation();
458→                    dispatch({ type: 'SKETCH_SHEET_DELETE', sheetId: sheet.id });
459→                    if (activeSheetId === sheet.id) {
460→                      editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
461→                      editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
462→                    }
463→                  }} aria-label="Delete Sheet" title="Delete Sheet">
464→                    <TrashIcon />
465→                  </button>
466→                </div>
467→              </TreeItem>
468→            );
469→          })}
470→        </div>
471→      </div>
472→    </div>
473→  );
474→}
